var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["git"] = TOPICS_DATA["git"] || {};
TOPICS_DATA["git"]["git-workflow"] = {"id":"git-workflow","title":"Git Workflows","difficulty":"intermediate","estimatedMinutes":20,"tldr":["A Git workflow is a convention for how teams use branches, commits, and merges to collaborate on code.","Common workflows: Git Flow (feature/release/hotfix branches), GitHub Flow (feature branch + PR to main), GitLab Flow (environment branches).","Choose a workflow based on team size, release frequency, and deployment strategy. Simple workflows suit small teams; complex ones suit regulated releases.","Key practices: feature branches for isolated work, pull requests for code review, protected branches for main/stable, and semantic commit messages."],"laymanDefinition":"Git workflows are like kitchen organization systems. Git Flow is a professional kitchen with stations for prep (feature), plating (release), and emergency (hotfix). GitHub Flow is a home kitchen: make your dish (branch), taste it (review), then serve (merge). GitLab Flow is meal-prep: stages for dev, staging, production.","deepDive":[{"heading":"Git Flow","text":"Classic workflow with main, develop, feature, release, and hotfix branches. Feature branches branch from develop. Release branches prepare a release. Hotfix branches fix production from main. Complex but thorough suitable for scheduled releases and maintenance versions."},{"heading":"GitHub Flow","text":"Simpler: main branch is always deployable. Create feature branches from main. Open PR for review and testing. Merge to main and deploy. No develop branch. No release branches. Suitable for continuous deployment and small teams."},{"heading":"GitLab Flow","text":"Environment branches: main/staging/production. Feature branches merge to main. Promote commits from main to staging to production via merge or cherry-pick. Supports environment-based promotion. Good for projects with multiple environments and compliance needs."},{"heading":"Trunk-Based Development","text":"Short-lived feature branches (hours/days). Frequent merges to main (trunk). Feature flags for incomplete work. Less merge conflicts faster CI continuous integration. Requires disciplined team and good test coverage."},{"heading":"Choosing a Workflow","text":"Git Flow: scheduled releases multiple versions large teams. GitHub Flow: continuous deployment startup/small team SaaS. GitLab Flow: multiple environments compliance gates. Trunk-Based: CI/CD DevOps maturity fast iterations."}],"interviewAnswer":"Choose the simplest workflow that meets your needs. Start with GitHub Flow or trunk-based development. Only adopt Git Flow if you need strict release management. The workflow is a tool not a rule adapt it to your team cadence and deployment strategy.","interviewQuestions":[{"question":"What is a Git workflow?","answer":"A convention for how teams use branches commits and merges to collaborate on code."},{"question":"What is Git Flow?","answer":"A workflow with main develop feature release and hotfix branches. Complex suitable for scheduled releases."},{"question":"What is GitHub Flow?","answer":"A simpler workflow: feature branches PRs to main deploy after merge. Suitable for continuous deployment."},{"question":"What is trunk-based development?","answer":"Short-lived feature branches frequent merges to main feature flags. Fast CI fewer merge conflicts."},{"question":"Which workflow is best for SaaS continuous deployment?","answer":"GitHub Flow or trunk-based development simple fast continuous."},{"question":"What is a hotfix branch?","answer":"A branch from main to fix a production issue quickly. Merged back to main and develop."},{"question":"What is a release branch?","answer":"A branch from develop to prepare a release. Only bug fixes and release tasks. Merged to main and develop."},{"question":"What is the main branch?","answer":"The production-ready branch. Always reflects the current production state. Typically protected."},{"question":"What is a feature branch?","answer":"A branch for developing a specific feature. Isolated from other changes until merged via PR."},{"question":"Should you use Git Flow or GitHub Flow?","answer":"Git Flow for scheduled releases and complex projects. GitHub Flow for simple CD pipelines."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Workflows</text><rect x=\"10\" y=\"35\" width=\"90\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"55\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Flow</text><text x=\"55\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Complex</text><rect x=\"10\" y=\"65\" width=\"90\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"55\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitHub Flow</text><text x=\"55\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Simple CD</text><rect x=\"10\" y=\"95\" width=\"90\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"55\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitLab Flow</text><text x=\"55\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Environments</text><rect x=\"10\" y=\"125\" width=\"90\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"55\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Trunk-Based</text><text x=\"55\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Feature flags</text><rect x=\"10\" y=\"155\" width=\"90\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"55\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Main</text><text x=\"55\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deployable</text><line x1=\"100\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"100\" y1=\"78\" x2=\"130\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"100\" y1=\"108\" x2=\"130\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"100\" y1=\"138\" x2=\"130\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"100\" y1=\"168\" x2=\"130\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"140\" y=\"35\" width=\"240\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"260\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Workflows</text><text x=\"260\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Conventions for branching merging and releasing code collaboratively.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Workflows: Git Flow GitHub Flow GitLab Flow Trunk-Based. Choose by team size and release cadence.</text></svg>","codeExamples":[{"title":"Git Flow Branch Setup","useCase":"Initialize Git Flow branches.","code":"# Initialize repository\ngit init\ngit checkout -b develop  # develop branch from main\n\n# Feature branch\ngit checkout -b feature/login develop\n# work on feature...\ngit checkout develop\ngit merge --no-ff feature/login\n\n# Release branch\ngit checkout -b release/v1.0 develop\n# bump version fix bugs...\ngit checkout main\ngit merge --no-ff release/v1.0\ngit tag -a v1.0 -m \"Release v1.0\"\ngit checkout develop\ngit merge --no-ff release/v1.0\n\n# Hotfix branch\ngit checkout -b hotfix/crash-fix main\n# fix bug...\ngit checkout main\ngit merge --no-ff hotfix/crash-fix\ngit tag -a v1.0.1 -m \"Hotfix v1.0.1\"\ngit checkout develop\ngit merge --no-ff hotfix/crash-fix","description":"Git Flow branch management with feature release and hotfix branches."},{"title":"GitHub Flow (PR Based)","useCase":"Simple continuous deployment workflow.","code":"# On main branch\ngit checkout main\ngit pull origin main\n\n# Create feature branch\ngit checkout -b feature/add-payment\n\n# Work and commit\ngit add .\ngit commit -m \"Add payment processing\"\ngit push -u origin feature/add-payment\n\n# Open Pull Request on GitHub\n# Team reviews CI runs tests\n# Merge via PR (squash or merge commit)\n\n# After merge delete branch\ngit branch -d feature/add-payment\ngit push origin --delete feature/add-payment","description":"GitHub Flow: feature branch PR review merge to main deploy."},{"title":"Trunk-Based with Feature Flags","useCase":"Continuous integration pattern.","code":"# Short-lived branch (hours)\ngit checkout -b feat-dark-mode\n\n# Work behind feature flag\n// Code: if (featureFlags.isEnabled('dark_mode')) {\n//   applyDarkMode();\n// }\n\ngit add .\ngit commit -m \"Add dark mode behind feature flag\"\ngit checkout main\ngit pull origin main\ngit merge feat-dark-mode\ngit push origin main\n\n# Enable feature in production gradually\n# featureFlags.enable(\"dark_mode\" user_percentage=10)\n\n# Remove branch remove flag later\ngit branch -d feat-dark-mode","description":"Trunk-based development with feature flags for incomplete or experimental features."},{"title":"Merge Strategy: Squash vs Rebase vs Merge","useCase":"Choose based on team practice.","code":"# Merge commit (preserves history)\ngit checkout main\ngit merge --no-ff feature-branch\n# Creates a merge commit with full branch history\n\n# Squash (clean linear history)\ngit merge --squash feature-branch\ngit commit -m \"Add feature XYZ\"\n# Single commit with all changes combined\n\n# Rebase (linear history without merge commits)\ngit checkout feature-branch\ngit rebase main\ngit checkout main\ngit merge feature-branch\n# Fast-forward clean linear history","description":"Squash keeps history clean merge preserves context rebase creates linear history."},{"title":"Git Workflow CLI Automation","useCase":"Scripted workflow enforcement.","code":"#!/bin/bash\n# Enforce branch naming convention\nBRANCH_NAME=$(git rev-parse --abbrev-ref HEAD)\n\nif [[ ! \"$BRANCH_NAME\" =~ ^(feature|bugfix|hotfix|release)/ ]]; then\n  echo \"Error: Branch must start with feature/ bugfix/ hotfix/ or release/\"\n  exit 1\nfi\n\n# Enforce commit message format\nCOMMIT_MSG_FILE=$1\nCOMMIT_MSG=$(cat \"$COMMIT_MSG_FILE\")\n\nif [[ ! \"$COMMIT_MSG\" =~ ^(feat|fix|docs|chore|refactor|test|ci): ]]; then\n  echo \"Error: Commit must start with feat: fix: docs: etc.\"\n  exit 1\nfi","description":"Automation scripts enforce branch naming and commit message conventions."}],"mcqQuestions":[{"question":"What is a Git workflow?","options":["Version control software","Convention for branching and merging","A type of Git command","File storage system"],"answer":1,"explanation":"A Git workflow defines how teams use branches commits and merges to collaborate."},{"question":"Which workflow has develop release and hotfix branches?","options":["GitHub Flow","Git Flow","Trunk-Based","GitLab Flow"],"answer":1,"explanation":"Git Flow uses main develop feature release and hotfix branches."},{"question":"What is the simplest workflow for CD?","options":["Git Flow","GitHub Flow","GitLab Flow","None"],"answer":1,"explanation":"GitHub Flow (feature branch PR to main to deploy) is simplest for continuous deployment."},{"question":"What enables trunk-based development for incomplete features?","options":["Long-lived branches","Feature flags","Separate repositories","Manual deployments"],"answer":1,"explanation":"Feature flags allow merging incomplete features to main without affecting users."},{"question":"What is a hotfix branch?","options":["Branch for new features","Branch from main for production fixes","Branch for experiments","Branch for documentation"],"answer":1,"explanation":"Hotfix branches branch from main to fix production issues quickly."},{"question":"What does --no-ff do in git merge?","options":["Fast-forward only","Forces merge commit even if fast-forward possible","No file changes","Skip commit hooks"],"answer":1,"explanation":"--no-ff creates a merge commit to preserve branch history."},{"question":"Git Workflows — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Workflows — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Workflows — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Workflows — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-branching"] = {"id":"git-branching","title":"Branching Strategies","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Branching strategy defines how teams create name use and delete branches to organize parallel development work.","Key concepts: branch naming conventions (feature/ bugfix/ hotfix/) branch lifecycle (create to work to merge to delete) protected branches.","Good branching reduces merge conflicts enables parallel work supports CI/CD and provides clear audit trail of changes.","Strategies: long-lived branches for environments (develop staging main) and short-lived branches for features and fixes."],"laymanDefinition":"Branching is like a tree of ideas. The trunk (main) is the stable reality. Branches are what if experiments what if we add a login screen what if we fix this bug what if we redesign the UI. Each branch grows independently then gets grafted back to the trunk when ready.","deepDive":[{"heading":"Branch Naming Conventions","text":"Standard prefixes: feature/add-login bugfix/fix-header hotfix/security-patch release/v1.2 chore/update-deps. Separators: slash (/) for category hyphen (-) for description. Include ticket number: feature/JIRA-123-checkout. Consistent naming enables automation (CI triggers branch cleanup)."},{"heading":"Protected Branches","text":"Branches that cannot be directly pushed to. Require PR reviews and passing CI. Typically: main develop staging production. Settings: require pull request require approvals (1-2) dismiss stale reviews require status checks require up-to-date branches include administrators."},{"heading":"Short-Lived vs Long-Lived Branches","text":"Short-lived: feature branches (hours-days). Merged quickly fewer conflicts faster integration. Long-lived: main develop staging (weeks-months). Represent environments or release trains. Best practice: minimize long-lived branches beyond what environments require."},{"heading":"Branch Deletion Strategy","text":"Delete feature branches after merge (both local and remote). Git: git branch -d feature-xyz && git push origin --delete feature-xyz. Automate with branch cleanup on PR merge. Exceptions: release branches preserved for LTS support hotfix branches for audit."},{"heading":"Git Bisect Friendly History","text":"Good branching creates a clean commit graph that git bisect can navigate. Merge commits mark integration points. Linear history (rebase/squash) is easier to bisect. Bad: deeply nested merge bubbles. Good: structured merges at clear boundaries."}],"interviewAnswer":"Consistent branching is the foundation of collaborative Git. Use clear naming conventions. Protect main and deployment branches. Delete branches after merge. Prefer short-lived branches. The branching strategy should serve the team delivery cadence not complicate it.","interviewQuestions":[{"question":"What is a branching strategy?","answer":"A convention for naming creating using and deleting branches to organize parallel development."},{"question":"What are protected branches?","answer":"Branches with restrictions: require PR reviews and CI status checks before merging."},{"question":"What is a good branch naming convention?","answer":"category/description: feature/login bugfix/fix-header hotfix/security-issue."},{"question":"Should you delete branches after merge?","answer":"Yes. Delete both local (git branch -d) and remote (git push origin --delete)."},{"question":"What is the difference between short-lived and long-lived branches?","answer":"Short-lived (hours-days): feature branches. Long-lived (weeks-months): main develop staging."},{"question":"What is a release branch?","answer":"A branch for stabilizing a release. Typically branched from develop merged to main and develop."},{"question":"How do you prevent direct pushes to main?","answer":"Configure branch protection rules in GitHub/GitLab/Bitbucket. Require PRs and approvals."},{"question":"What is a feature branch?","answer":"A branch for developing a specific feature branched from develop or main."},{"question":"How do you handle multiple concurrent features?","answer":"Each feature in its own branch. Merge conflicts resolved during PR/integration."},{"question":"What is the purpose of branch naming conventions?","answer":"Organization automation (CI/CD triggers) team communication and audit trails."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Branching Strategies</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Branch Naming</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">feature/login</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Protected Branch</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Requires PR + CI</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Short-Lived</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Hours to days</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Long-Lived</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Environments</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Delete After</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Clean up merged</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"275\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Branching Strategies</text><text x=\"275\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Naming protection lifecycle and cleanup conventions for collaboration.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Branching Strategies: Naming conventions branch protection lifecycle management and cleanup practices.</text></svg>","codeExamples":[{"title":"Branch Protection (GitHub CLI)","useCase":"Configure protected branch.","code":"# Protect main branch via GitHub API/CLI\ngh api repos/:owner/:repo/branches/main/protection \\\n  --method PUT \\\n  -f required_status_checks.strict=true \\\n  -f required_status_checks.contexts[]=\"continuous-integration\" \\\n  -f enforce_admins=true \\\n  -f required_pull_request_reviews.required_approving_review_count=2 \\\n  -f restrictions.users[]=\"admin-team\"\n\n# Or use GitHub UI: Settings > Branches > Add rule\n# Pattern: main develop release/*","description":"Branch protection enforces PRs reviews and CI checks before merging."},{"title":"Branch Cleanup Script","useCase":"Delete merged branches.","code":"#!/bin/bash\n# Delete local branches merged into main\ngit branch --merged main | grep -v \"*|main|develop\" | xargs -n 1 git branch -d\n\n# List remote merged branches\ngit branch -r --merged origin/main | grep -v \"origin/main|origin/develop\"\n\n# Delete remote merged branches\ngit branch -r --merged origin/main | grep -v \"origin/main|origin/develop\" |\n  sed 's/origin///' | xargs -I {} git push origin --delete {}\n\n# Automate via CI on PR merge\necho \"::warning::Feature branch cleanup recommended\"","description":"Automated cleanup of merged branches keeps the repository tidy."},{"title":"Branch from Issue (GitHub CLI)","useCase":"Create branch linked to issue.","code":"# Create branch from issue\ngh issue view 42 --json number title labels\n\n# Create and switch to feature branch\nISSUE_NUMBER=42\nISSUE_TITLE=$(gh issue view $ISSUE_NUMBER --json title -q .title)\nBRANCH_NAME=\"feature/$(echo $ISSUE_TITLE |\n  sed 's/[^a-zA-Z0-9]/-/g' |\n  tr '[:upper:]' '[:lower:]' | cut -c1-50)\"\n\ngit checkout -b \"$BRANCH_NAME\" main\ngit push -u origin \"$BRANCH_NAME\"\n\n# Create PR linked to issue\ngh pr create --fill --issue $ISSUE_NUMBER","description":"Automate branch creation from issues with standardized naming."},{"title":"Branching Diagram Generation","useCase":"Visualize branch structure.","code":"# Show branch graph\ngit log --graph --oneline --all --decorate\n\n# Pretty graph with aliases\ngit config --global alias.tree \"log --graph --oneline --all --decorate --simplify-by-decoration\"\ngit tree\n\n# Show branches with last commit\ngit branch -v\n\n# Show merged/unmerged branches\ngit branch --merged main\ngit branch --no-merged main\n\n# Visualize with tools:\n# gitk --all\n# git log --graph --format=\"%C(auto)%h %d %s\"","description":"Visualize branch structure for audit and understanding."},{"title":"Branch Lifecycle Hooks","useCase":"Automate branch events.","code":"#!/bin/bash\n# .git/hooks/post-checkout (on branch switch)\nPREV_HEAD=$1\nNEW_HEAD=$2\nIS_BRANCH_SWITCH=$3\n\nif [ \"$IS_BRANCH_SWITCH\" = \"1\" ]; then\n  BRANCH=$(git rev-parse --abbrev-ref HEAD)\n  echo \"Switched to branch: $BRANCH\"\n  \n  # Run post-checkout tasks\n  if [ -f \"Makefile\" ]; then\n    make install-deps 2>/dev/null || true\n  fi\nfi","description":"Git hooks automate tasks on branch checkout helping enforce conventions."}],"mcqQuestions":[{"question":"What is a good branch prefix for a new feature?","options":["release/","feature/","hotfix/","bugfix/"],"answer":1,"explanation":"feature/ is the standard prefix for feature branches."},{"question":"What does a protected branch require?","options":["Direct push","Pull request and approvals","Email notification","Manual backup"],"answer":1,"explanation":"Protected branches require PRs reviews and CI checks no direct pushes."},{"question":"When should you delete a branch?","options":["Before creating it","After merging to main/develop","After pushing once","Never"],"answer":1,"explanation":"Delete branches after they are merged to keep the repository clean."},{"question":"What is a short-lived branch?","options":["A branch that lasts months","A branch that lasts hours to days","A branch never merged","A branch for documentation"],"answer":1,"explanation":"Short-lived branches (feature branches) are merged within hours to days."},{"question":"How do you prevent pushes to main?","options":["Branch protection rules","Delete main branch","Make repo read-only","Use .gitignore"],"answer":0,"explanation":"Branch protection rules enforce PR-based workflow on main/develop branches."},{"question":"What does git branch -d do?","options":["Creates a branch","Deletes a merged branch","Renames a branch","Lists branches"],"answer":1,"explanation":"git branch -d deletes a branch that has been merged (safe delete)."},{"question":"Branching Strategies — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Branching Strategies — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Branching Strategies — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Branching Strategies — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-merge"] = {"id":"git-merge","title":"Git Merge","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Git merge integrates changes from one branch into another combining the development histories of both branches.","Three-way merge: Git finds the common ancestor of two branches and applies changes from both sides. Conflicts arise when the same lines changed differently.","Fast-forward merge: when the target branch has not diverged Git simply moves the pointer forward (no merge commit). Use --no-ff to force a merge commit.","Conflict resolution: manually edit conflicted files mark as resolved with git add and complete the merge with git commit or git merge --continue."],"laymanDefinition":"Git merge is like merging two rivers into one. If both rivers flowed from the same source and one has moved ahead (fast-forward) you just follow the advanced river. If they diverged around an island (branching) you create a new combined channel (merge commit). Sometimes the waters clash that is a merge conflict.","deepDive":[{"heading":"Three-Way Merge Algorithm","text":"Git identifies the merge base (common ancestor commit). It creates two diff hunks: base to branch A and base to branch B. Then applies both diffs to create the result. If both diffs modify the same lines differently you get a conflict. Git uses the longest common subsequence algorithm."},{"heading":"Fast-Forward Merge","text":"When target branch (main) has not moved since the source branch (feature) was created Git can simply advance main pointer to feature tip. No merge commit. Use git merge --no-ff to always create a merge commit for history preservation."},{"heading":"Recursive Merge Strategy","text":"Default for non-fast-forward merges. When there are multiple merge bases (common ancestors) Git merges them first to create a virtual ancestor then performs the three-way merge. Handles criss-cross merge scenarios with multiple possible ancestors."},{"heading":"Conflict Resolution Strategies","text":"Accept ours: keep current branch version (--ours). Accept theirs: keep incoming branch version (--theirs). Manual: edit file remove conflict markers (<<<<<<< ======= >>>>>>>). Merge tools: vimdiff VS Code meld Beyond Compare. After resolving: git add file && git merge --continue."},{"heading":"Merge Drivers","text":"Custom merge drivers for specific file types. .gitattributes: *.pdf merge=binary. Configured in .git/config. Useful for: lock files compiled outputs auto-generated code. Git also supports: union merge (combine both changes) subtree merge (merge subproject into subdirectory)."}],"interviewAnswer":"Merging is the core of Git collaboration. Understand the three-way merge algorithm. Use --no-ff to preserve feature branch history. Resolve conflicts carefully test after conflict resolution. Configure merge drivers for binary/specialized files. Practice conflict resolution it becomes easier with experience.","interviewQuestions":[{"question":"What is git merge?","answer":"Integrates changes from one branch into another combining development histories."},{"question":"What is a three-way merge?","answer":"Merge using common ancestor + two branch tips. Git finds base creates diffs from base to each branch applies both."},{"question":"What is a fast-forward merge?","answer":"When target branch has not diverged Git simply advances the pointer. No merge commit."},{"question":"What is a merge conflict?","answer":"When two branches modified the same lines differently. Git cannot automatically resolve. Manual intervention needed."},{"question":"How do you resolve a merge conflict?","answer":"Edit conflicted files remove >>> <<< markers git add file git merge --continue."},{"question":"What does --no-ff do?","answer":"Forces a merge commit even when fast-forward is possible. Preserves branch history."},{"question":"What is the merge base?","answer":"The common ancestor commit of two branches. Git computes diffs from this base."},{"question":"How do you abort a merge?","answer":"git merge --abort. Returns to pre-merge state."},{"question":"What is a recursive merge?","answer":"Default strategy for non-FF merges. Handles multiple merge bases by creating a virtual ancestor."},{"question":"What is git mergetool?","answer":"Launches a visual merge tool (vimdiff VS Code meld) to resolve conflicts interactively."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Merge</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Branch A</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Feature work</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Branch B</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Main branch</text><line x1=\"50\" y1=\"90\" x2=\"50\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"80\" y1=\"90\" x2=\"80\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"120\" width=\"75\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"47.5\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Base</text><text x=\"47.5\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Common ancestor</text><rect x=\"95\" y=\"120\" width=\"75\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"132.5\" y=\"136\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Merge</text><text x=\"132.5\" y=\"148\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Three-way combine</text><rect x=\"10\" y=\"155\" width=\"160\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"90\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result</text><text x=\"90\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Combined history + merge commit</text><line x1=\"170\" y1=\"48\" x2=\"200\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"170\" y1=\"78\" x2=\"200\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"50\" y1=\"145\" x2=\"50\" y2=\"155\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"80\" y1=\"145\" x2=\"80\" y2=\"155\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"210\" y=\"35\" width=\"170\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"295\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Merge</text><text x=\"295\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Three-way merge: base + branch A + branch B to merged result. Conflicts need manual resolution.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Merge: Integrate branches via three-way merge. Fast-forward merge commits and conflict resolution.</text></svg>","codeExamples":[{"title":"Basic Git Merge Commands","useCase":"Common merge operations.","code":"# Merge feature into main\ngit checkout main\ngit pull origin main\ngit merge feature/login\n\n# Force merge commit (no fast-forward)\ngit merge --no-ff feature/login\n\n# Merge with custom message\ngit merge --no-ff -m \"feat: integrate login feature\" feature/login\n\n# Abort merge\ngit merge --abort\n\n# Check merge status\ngit status\ngit merge --continue  # after resolving conflicts","description":"Essential merge commands: merging fast-forward control abort and continue."},{"title":"Resolving Merge Conflicts","useCase":"Manual conflict resolution workflow.","code":"# Attempt merge conflict occurs\ngit merge feature/login\n>> Auto-merge failed; fix conflicts then commit\n\n# View conflicted files\ngit status\n# both modified: src/auth.js\n\n# Open file conflict markers:\n# <<<<<<< HEAD\n#   const timeout = 5000;\n# =======\n#   const timeout = 10000;\n# >>>>>>> feature/login\n\n# Edit file to resolve\n# const timeout = 7500; // compromise\n\n# Mark as resolved\ngit add src/auth.js\n\n# Complete merge\ngit merge --continue\n# or: git commit -m \"Merge feature/login into main\"","description":"Resolve merge conflicts by editing files removing markers and completing the merge."},{"title":"Merge with Strategy Options","useCase":"Advanced merge strategies.","code":"# Our strategy (keep current branch)\ngit merge -Xours feature/branch\n# Keeps current branch version on conflicts\n\n# Their strategy (keep incoming)\ngit merge -Xtheirs feature/branch\n# Keeps incoming branch version on conflicts\n\n# Recursive with patience (better diffs)\ngit merge -Xpatience feature/branch\n# Slower but produces cleaner merge results\n\n# Squash merge (combine all into one commit)\ngit merge --squash feature/branch\ngit commit -m \"feat: add login feature\"\n\n# Verify merge\ngit log --oneline --graph -5\ngit diff --stat main@{1} main","description":"Advanced merge strategies for specific conflict resolution needs."},{"title":"Merge Queue (GitHub Merge Queue)","useCase":"Automated merge ordering.","code":"# GitHub Merge Queue merges PRs in order\n# Ensures each PR passes CI after merging\n# with current main not at PR creation time\n\n# Enable in repo settings:\n# Settings > Branches > Branch protection >\n# \"Require merge queue\"\n\n# Workflow:\n# 1. PR approved + CI passes\n# 2. Add to merge queue (via UI or label)\n# 3. Queue creates a temporary branch\n#    merging all queued PRs in order\n# 4. CI runs on combined merge\n# 5. If passes merged to main","description":"Merge queues ensure each PR merges cleanly against the latest main state."},{"title":"Automated Merge Conflict Detection (CI)","useCase":"Prevent conflicting PRs.","code":"# CI job: check if PR branch can merge cleanly\n\nname: Merge Check\non: pull_request\njobs:\n  check-merge:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: |\n          git fetch origin main\n          if ! git merge-base --is-ancestor\n            origin/main HEAD; then\n            echo \"Branch needs rebase on main\"\n            exit 1\n          fi\n      - run: |\n          git merge --no-commit origin/main\n          if [ $? -ne 0 ]; then\n            git merge --abort\n            echo \"Merge conflict detected resolve locally\"\n            exit 1\n          fi\n          git merge --abort","description":"CI checks detect merge conflicts early in the PR workflow."}],"mcqQuestions":[{"question":"What is a three-way merge?","options":["Two branches merging directly","Merge using common ancestor and two tips","Merging three branches at once","Deleting old branches"],"answer":1,"explanation":"Three-way merge uses the common ancestor and both branch tips to create the merge."},{"question":"What causes a merge conflict?","options":["Both branches modified same lines differently","A file was deleted","The repository is corrupted","Git is out of memory"],"answer":0,"explanation":"Conflicts occur when the same lines are modified in both branches."},{"question":"What does --no-ff do?","options":["No fast-forward","Force merge commit","No file changes","Fast-forward only"],"answer":1,"explanation":"--no-ff forces a merge commit even when fast-forward is possible."},{"question":"How do you abort a merge?","options":["git merge --stop","git merge --abort","git reset --merge","git checkout main"],"answer":1,"explanation":"git merge --abort returns to the pre-merge state."},{"question":"What is the default merge strategy?","options":["Ours","Recursive","Octopus","Subtree"],"answer":1,"explanation":"Recursive is the default strategy for non-fast-forward merges."},{"question":"What does git merge --squash do?","options":["Squashes commits into one","Deletes the source branch","Adds squash game","Compresses the repo"],"answer":0,"explanation":"Squash merge combines all feature branch commits into a single commit."},{"question":"Git Merge — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Merge — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Merge — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Merge — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-rebase"] = {"id":"git-rebase","title":"Git Rebase","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Git rebase rewrites commit history by applying commits from one branch onto the tip of another creating a linear history.","Unlike merge (creates a merge commit) rebase replays each commit one by one. The result is a clean linear history without merge bubbles.","Interactive rebase (git rebase -i) allows squashing reordering editing dropping and rewording commits. Powerful but dangerous on shared branches.","Golden rule: never rebase commits that have been pushed to a shared branch. Rebase only local/feature branches before merging."],"laymanDefinition":"Rebase is like rewriting the history of a movie. You have a rough cut (your branch) with scenes in a messy order. Interactive rebase lets you reorder scenes combine similar shots (squash) delete unneeded footage and retitle scenes. But once you have shown the movie to others (pushed) changing the order confuses everyone.","deepDive":[{"heading":"Rebase vs Merge","text":"Rebase: linear history no merge commits cleaner log. Rewrites commit SHAs. Merge: preserves branch topology keeps original commit order and SHAs. Rule of thumb: rebase for feature branches before merging merge for shared integration branches."},{"heading":"Interactive Rebase Operations","text":"pick: use commit as-is. reword: change commit message. edit: stop to amend commit (content or message). squash: combine with previous commit merge messages. fixup: like squash but discard this commit message. drop: remove commit. exec: run shell command. break: stop at this point."},{"heading":"Rebase Workflow","text":"git checkout feature-branch && git rebase main: takes all feature commits and replays them on top of main current tip. Resolve conflicts per commit. After successful rebase: git checkout main && git merge feature-branch (fast-forward). Result: linear history."},{"heading":"Rebase Conflicts","text":"Unlike merge (one big conflict resolution) rebase resolves conflicts per commit. Each commit is applied in order. If commit A conflicts: resolve git add git rebase --continue. If stuck: git rebase --abort. If skip: git rebase --skip. Per-commit resolution makes debugging easier."},{"heading":"Rebase Recovery (Rebase Dangers)","text":"If you accidentally rebase a pushed branch: git rebase --abort (if still in progress). If completed: git reflog to find the old commit git reset --hard ORIG_HEAD or git checkout -b recovery <old-sha>. For shared branches: force push is destructive communicate with team first."}],"interviewAnswer":"Use rebase to keep feature branch history clean before merging. Never rebase shared branches. Interactive rebase is a powerful tool for curating commit history. Resolve conflicts per commit during rebase. If unsure use merge it is safer. Reflog is your safety net for recovery.","interviewQuestions":[{"question":"What is git rebase?","answer":"Rewrites commit history by applying commits from one branch onto the tip of another. Creates linear history."},{"question":"What is the difference between rebase and merge?","answer":"Rebase: linear history rewrites SHAs. Merge: preserves branch topology adds merge commit."},{"question":"What is the golden rule of rebasing?","answer":"Never rebase commits that have been pushed to a shared branch. Rebase only local feature branches."},{"question":"What is interactive rebase?","answer":"git rebase -i opens an editor to pick reword edit squash fixup or drop commits."},{"question":"How do you resolve conflicts during rebase?","answer":"Conflicts are resolved per commit. Fix file git add git rebase --continue. Abort with git rebase --abort."},{"question":"What does squash do in interactive rebase?","answer":"Combines a commit with the previous one. Both commit messages are merged into one."},{"question":"What does fixup do vs squash?","answer":"Fixup combines without keeping the commit message. Squash combines and merges messages."},{"question":"How do you recover from a bad rebase?","answer":"git reflog to find the old commit SHA. git reset --hard <old-sha> or create a branch from it."},{"question":"When should you prefer merge over rebase?","answer":"For shared branches when you want to preserve exact history or when the rebase would cause excessive conflict resolution."},{"question":"What happens to commit SHAs after rebase?","answer":"They change. Each commit is a new commit object with a new SHA even if the content is the same."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Rebase</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Feature Branch</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Commit A Commit B</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Main Tip</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Latest main</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rebase</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Replay commits on main tip</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Linear History</text><text x=\"215\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">A B on top of main</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Interactive</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">-i: squash reword drop</text><rect x=\"10\" y=\"135\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"65\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Conflict</text><text x=\"65\" y=\"163\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Resolve per commit</text><rect x=\"10\" y=\"165\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"65\" y=\"181\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Merge</text><text x=\"65\" y=\"193\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast-forward after rebase</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Rebase</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Rewrite commits onto another branch. Clean linear history. Interactive mode for curation.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Rebase: Reapply commits on a new base. Linear history. Interactive commit curation. Never rebase shared branches.</text></svg>","codeExamples":[{"title":"Basic Rebase Workflow","useCase":"Rebase feature branch onto main.","code":"# Start on feature branch\ngit checkout feature/login\n\n# Rebase onto main\ngit rebase main\n>> Applying: Add login form\n>> Applying: Add validation logic\n>> Applying: Add OAuth handler\n\n# If conflict occurs:\n# 1. Fix conflicts in file\n# 2. git add <file>\n# 3. git rebase --continue\n# Or: git rebase --abort\n\n# After successful rebase\ngit checkout main\ngit merge feature/login\n# Fast-forward merge linear history","description":"Standard rebase workflow: rebase feature onto main resolve conflicts per commit then merge."},{"title":"Interactive Rebase (Squash Commits)","useCase":"Clean up before PR.","code":"# Rebase last 4 commits interactively\ngit rebase -i HEAD~4\n\n# Editor opens:\n# pick a1b2c3d Add login form\n# pick e4f5g6h Fix typo in login\n# pick i7j8k9l Add validation\n# pick m0n1o2p Fix validation bug\n\n# Change to:\n# pick a1b2c3d Add login form\n# fixup e4f5g6h Fix typo in login\n# squash i7j8k9l Add validation\n# fixup m0n1o2p Fix validation bug\n\n# Save and exit. Result: 2 clean commits:\n# a1b2c3d Add login form\n# i7j8k9l Add validation (with test fixes squashed)","description":"Interactive rebase squashes fixup commits into meaningful feature commits before PR."},{"title":"Rebase with --onto","useCase":"Rebase onto a different base.","code":"# Scenario: feature-b was branched from feature-a\n# But feature-a is not ready; we want feature-b on main\n\n# Before:\n# main -- A -- B\n#          \\\n#           C -- D (feature-a)\n#                 \\\n#                  E -- F (feature-b)\n\n# Rebase feature-b directly onto main\ngit rebase --onto main feature-a feature-b\n\n# After:\n# main -- A -- B -- E -- F (feature-b)\n#          \\\n#           C -- D (feature-a)\n\n# Or shorter:\ngit checkout feature-b\ngit rebase --onto main feature-a","description":"git rebase --onto allows selective rebasing onto a different base branch."},{"title":"Avoid Rebase on Shared Branches","useCase":"Why not to rebase pushed branches.","code":"# What happens when you rebase a shared branch:\n\n# Alice pulls feature/xyz (commit A B C)\n# Alice rebases onto updated main:\ngit checkout feature/xyz\ngit rebase main  # A B C (new SHAs!)\ngit push --force-with-lease\n\n# Bob already has A B C locally\n# Bob pulls: Git sees divergence\n# Bob Git says:\n# hint: you have divergent branches\n\n# Bob options (all bad):\n# git pull --rebase (rewrites again)\n# git reset --hard (loses work)\n# Manual fix required\n\n# SAFE: use merge on shared branches\n# OR: team agreement on a single owner","description":"Rebasing shared branches causes divergence for other developers. Use merge instead."},{"title":"Rebase and Auto-Squash","useCase":"Automatically squash fixup commits.","code":"# Commit fixup commits with --fixup\ngit commit --fixup a1b2c3d\n# Creates \"fixup! Add login form\" commit\n\n# Later rebase with --autosquash\ngit rebase -i --autosquash HEAD~10\n# Automatically moves fixup commits\n# next to their target commits\n# and marks them as fixup\n\n# One-liner:\ngit commit --fixup <target-sha>\ngit rebase -i --autosquash <base>\n\n# Enable automatic autosquash:\ngit config --global rebase.autosquash true","description":"--fixup and --autosquash automate the squash workflow for related commits."}],"mcqQuestions":[{"question":"What does rebase do?","options":["Creates a merge commit","Reapplies commits on a new base","Deletes old commits","Stages all files"],"answer":1,"explanation":"Rebase replays commits from one branch onto the tip of another."},{"question":"What is the golden rule of rebasing?","options":["Always rebase main","Never rebase shared branches","Rebase every hour","Only rebase with --force"],"answer":1,"explanation":"Never rebase commits that have been pushed to a shared branch."},{"question":"What does interactive rebase allow?","options":["Only fast-forward","Squash reword drop reorder commits","Delete remote branches","Create new branches"],"answer":1,"explanation":"Interactive rebase (git rebase -i) allows full commit history curation."},{"question":"How do you resolve conflicts during rebase?","options":["One big conflict resolution","Per commit then git rebase --continue","Skip conflicted commits","Delete conflicted files"],"answer":1,"explanation":"Rebase resolves conflicts per commit fix add continue."},{"question":"What happens to commit SHAs after a rebase?","options":["They stay the same","They change (new commits)","They are deleted","They get encrypted"],"answer":1,"explanation":"Rebase creates new commit objects with new SHAs even for identical content."},{"question":"What is the difference between squash and fixup?","options":["Squash keeps message fixup discards it","Fixup keeps message squash discards","They are the same","Fixup deletes the commit"],"answer":0,"explanation":"Squash merges commit messages; fixup discards the squashed commit message."},{"question":"Git Rebase — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Rebase — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Rebase — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Rebase — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-stash"] = {"id":"git-stash","title":"Git Stash","difficulty":"beginner","estimatedMinutes":10,"tldr":["Git stash temporarily saves uncommitted changes (modified tracked files and staged changes) so you can work on something else.","Stash takes your working directory and staging area changes and saves them on a stack of unfinished changes. Your working directory becomes clean.","Common use: switching branches without committing half-finished work pulling remote changes or trying a quick experiment.","Stash operations: git stash (save) git stash pop (apply + drop) git stash apply (keep on stack) git stash list git stash drop."],"laymanDefinition":"Git stash is like putting your bookmarks in a drawer while you clean your desk. You are reading chapter 5 (working on feature X) but need to answer the door (switch to urgent bug fix). You put a bookmark (stash) in your book set it aside answer the door then come back and resume from the bookmark.","deepDive":[{"heading":"What Git Stash Saves","text":"Modified tracked files (unstaged changes). Staged changes (the index). Untracked files (with -u or --include-untracked). Ignored files (with -a or --all). New files (created but not tracked). Stash does NOT save: new branches new commits or the working tree for untracked/ignored files unless specified."},{"heading":"Stash Stack Management","text":"Stashes are stored on a stack (LIFO). Latest stash is stash@{0}. List all: git stash list. Apply specific: git stash apply stash@{2}. Drop: git stash drop stash@{1}. Clear all: git stash clear. Create branch from stash: git stash branch new-branch stash@{0}."},{"heading":"Stash Partial Changes","text":"Interactive stash: git stash -p (patch mode) lets you select which hunks to stash. Keep staged changes: git stash --keep-index (stashes only unstaged changes). Stash specific file: git stash push -m \"wip\" -- filename. Create stash from a specific commit: not directly supported (use git format-patch instead)."},{"heading":"Stash Use Cases","text":"1. Urgent bug fix: stash feature work switch to main fix bug switch back pop stash. 2. Pull conflicts: stash local changes pull pop stash (may have conflicts). 3. Experiment: stash try approach if fails drop stash if works pop stash. 4. Rebase preparation: stash before rebase if you have uncommitted changes."},{"heading":"Stash Limitations and Alternatives","text":"Stash is local-only cannot be pushed/shared. Not ideal for long-term storage (use feature branches). Large stashes can be confusing (use descriptive messages: git stash push -m \"WIP: login form validation\"). Alternative for complex workflows: commit on a temporary branch instead of stashing."}],"interviewAnswer":"Stash is perfect for short-term interruptions. Use descriptive messages (git stash push -m \"message\"). For complex or long-term work-in-progress create a temporary branch instead. Stash has limitations: local-only stack-based no easy diffing between stashes. Practice the difference between pop and apply.","interviewQuestions":[{"question":"What is git stash?","answer":"Temporarily saves uncommitted changes to a stack cleaning the working directory for other tasks."},{"question":"What does git stash save?","answer":"Modified tracked files and staged changes. Untracked files with -u flag."},{"question":"What is the difference between stash pop and stash apply?","answer":"Pop: applies and removes from stack. Apply: applies but keeps on stack."},{"question":"How do you list stashes?","answer":"git stash list. Shows stack with stash@{0} stash@{1} etc."},{"question":"How do you stash untracked files?","answer":"git stash -u or git stash --include-untracked."},{"question":"What is the most recent stash?","answer":"stash@{0} (top of the stack)."},{"question":"How do you apply a specific stash?","answer":"git stash apply stash@{2}."},{"question":"How do you clear all stashes?","answer":"git stash clear. Be careful this is permanent."},{"question":"Can you push a stash to remote?","answer":"No. Stashes are local-only. Use branches for shared work-in-progress."},{"question":"What is git stash -p?","answer":"Patch mode interactively select hunks to stash. Useful for partial stashing."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Stash</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Working Dir</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Uncommitted changes</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Stash Stack</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">stash@{0} stash@{1}</text><line x1=\"120\" y1=\"75\" x2=\"150\" y2=\"75\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Clean Dir</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Switch branches</text><line x1=\"120\" y1=\"102\" x2=\"150\" y2=\"102\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pop/Apply</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Restore changes</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Drop</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Remove from stack</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Clear</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Remove all stashes</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Stash</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Temporarily save uncommitted changes. Stack-based. Perfect for interruptions.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Stash: Save uncommitted work temporarily. Switch branches pop later. Stack-based management.</text></svg>","codeExamples":[{"title":"Basic Stash Operations","useCase":"Save and restore stashes.","code":"# Save uncommitted changes\ngit stash\n# Working directory is now clean\n\n# Save with message\ngit stash push -m \"WIP: login validation\"\n\n# Apply most recent stash and remove from stack\ngit stash pop\n\n# Apply most recent stash without removing\ngit stash apply\n\n# Apply specific stash\ngit stash apply stash@{1}\n\n# List all stashes\ngit stash list\n# stash@{0}: WIP: login validation\n# stash@{1}: WIP: header fix","description":"Core stash commands: save pop apply list. Use messages for clarity."},{"title":"Stashing Untracked and All Files","useCase":"Include new/ignored files.","code":"# Stash including untracked files\ngit stash -u\n# or: git stash --include-untracked\n\n# Stash ALL files (including ignored)\ngit stash -a\n# or: git stash --all\n\n# Check what a stash contains\ngit stash show stash@{0}\ngit stash show -p stash@{0}\n\n# Example workflow:\necho \"config.local\" >> .gitignore\ngit stash -a # saves everything\ngit stash list","description":"Use -u for untracked files -a for all files including ignored ones."},{"title":"Stash Branch (Recovery)","useCase":"Create branch from stash.","code":"# If you pop a stash and it conflicts:\ngit stash pop\n# Auto-merge failed to conflicts\n\n# Better: create a branch from the stash\n# This recreates the original commit state\ngit stash branch recovery-branch stash@{0}\n# Creates branch applies stash drops stash\n\n# Now you have a proper branch to work on\ngit add .\ngit commit -m \"Restore stashed work\"\n\n# Useful when:\n# - Stash conflicts with current branch\n# - You forgot what branch the stash was from","description":"git stash branch creates a branch from a stash for clean recovery."},{"title":"Stash Across Branches","useCase":"Managing multiple contexts.","code":"# On feature/login branch\ngit stash push -m \"half-done login form\"\n\n# Switch to bugfix\ngit checkout main\ngit checkout -b bugfix/crash-fix\n# Fix the bug...\ngit add .\ngit commit -m \"fix: prevent crash on empty input\"\n\n# Switch back to feature\ngit checkout feature/login\n\n# Restore stashed work\ngit stash pop\n\n# If stashed work was on different base\n# you may get conflicts (resolve normally)\n\n# Alternative: apply and keep stash until resolved\ngit stash apply  # then resolve commit git stash drop","description":"Stash enables context switching between branches without losing uncommitted work."},{"title":"Interactive Stash (Patch Mode)","useCase":"Selective stashing.","code":"# Interactive stash select hunks\ngit stash -p\n\n# Git shows each change hunk:\n# diff --git a/src/auth.js b/src/auth.js\n# @@ -10 5 +10 8 @@\n#  console.log(\"init\");\n# +const debug = true;  to proposed change\n# Stash this hunk? [y n q a d / j J g e ?]\n\n# Keep staged changes stash unstaged only\ngit stash --keep-index\n# Staged changes remain in working directory\n# Unstaged changes go to stash\n\n# Stash specific file\ngit stash push -m \"config changes\" -- src/config.js","description":"Patch mode allows stashing specific changes while keeping others in the working directory."}],"mcqQuestions":[{"question":"What does git stash do?","options":["Commits changes","Saves changes temporarily","Deletes changes","Pushes to remote"],"answer":1,"explanation":"Stash temporarily saves uncommitted changes on a stack."},{"question":"What is the difference between pop and apply?","options":["Pop applies and removes apply keeps","Pop keeps apply removes","No difference","Pop is for remote apply is local"],"answer":0,"explanation":"Pop removes from stack after applying; apply keeps it on the stack."},{"question":"How do you stash untracked files?","options":["git stash -u","git stash --all","git stash -p","Cannot stash untracked"],"answer":0,"explanation":"Use git stash -u or --include-untracked for untracked files."},{"question":"What is stash@{0}?","options":["The oldest stash","The most recent stash","A specific file","An error message"],"answer":1,"explanation":"stash@{0} is the top (most recent) item on the stash stack."},{"question":"Can you share stashes with your team?","options":["Yes via git push","No stashes are local","Only with GitHub","Via email"],"answer":1,"explanation":"Stashes are local-only and cannot be pushed to a remote repository."},{"question":"How do you clear all stashes?","options":["git stash drop","git stash clear","git stash remove","git stash delete"],"answer":1,"explanation":"git stash clear removes all stashes from the stack permanently."},{"question":"Git Stash — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Stash — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Stash — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Stash — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-tag"] = {"id":"git-tag","title":"Git Tags","difficulty":"beginner","estimatedMinutes":10,"tldr":["Git tags are references that point to specific commits typically used to mark release points (v1.0 v2.0 v1.0.1-rc1).","Two types: lightweight (just a pointer to a commit) and annotated (stored as full objects with message author date GPG signature).","Annotated tags are recommended for releases: they include the tagger name email date message and can be GPG-signed for verification.","Tags are not automatically pushed to remote. Must explicitly push: git push origin --tags or git push origin <tag-name>."],"laymanDefinition":"Git tags are like sticky notes on a timeline. You mark important points: Version 1.0 released here Version 1.1 released here. Annotated tags are sticky notes with detailed notes attached. Lightweight tags are just a colored dot. You can go back to any tagged point easily.","deepDive":[{"heading":"Lightweight vs Annotated Tags","text":"Lightweight: git tag v1.0. Just a name pointing to a commit. No metadata. Annotated: git tag -a v1.0 -m \"Release v1.0\". Stored as a full Git object with message date tagger optional GPG signature. Always use annotated tags for releases."},{"heading":"Tag Naming Conventions","text":"Semantic versioning: v1.2.3 (major.minor.patch). Pre-release: v1.2.3-rc1 v1.2.3-beta. Version prefix: v (v1.0) or no prefix (1.0). Leading v is conventional. Build metadata: v1.2.3+build.456. Suffix: v1.2.3-lts. Consistency within project is most important."},{"heading":"GPG-Signed Tags","text":"Annotated tags can be GPG-signed: git tag -s v1.0 -m \"Release v1.0\". Provides cryptographic verification that the tag was created by you. Verification: git tag -v v1.0. Requires GPG key setup. Signed tags ensure release authenticity."},{"heading":"Tag Operations","text":"Create: git tag -a v1.0 -m \"Release\". List: git tag git tag -l \"v1.*\". Show: git show v1.0. Delete local: git tag -d v1.0. Delete remote: git push --delete origin v1.0. Push: git push origin v1.0 git push origin --tags. Checkout: git checkout v1.0 (detached HEAD)."},{"heading":"Tags in CI/CD","text":"Tags trigger release pipelines. GitHub Actions: on push tags. GitLab CI: only: tags. Semantic versioning from tags: git describe --tags --abbrev=0. Auto-build on tag push. Tags vs branches for releases: tags are immutable branches can move. Always tag after release merge to main."}],"interviewAnswer":"Use annotated tags for all releases. Follow semantic versioning (v1.2.3). GPG-sign tags for security. Push tags explicitly they do not auto-push with commits. Tags are immutable references once set they should not be deleted or moved unless absolutely necessary.","interviewQuestions":[{"question":"What is a Git tag?","answer":"A reference pointing to a specific commit typically used to mark release points."},{"question":"What are the two types of Git tags?","answer":"Lightweight (just a pointer) and Annotated (full object with message author date signature)."},{"question":"Which tag type should you use for releases?","answer":"Annotated tags (-a flag) they include metadata and can be GPG-signed."},{"question":"How do you push tags to remote?","answer":"git push origin <tag-name> or git push origin --tags (pushes all tags)."},{"question":"How do you delete a local tag?","answer":"git tag -d v1.0"},{"question":"How do you delete a remote tag?","answer":"git push --delete origin v1.0 or git push origin :refs/tags/v1.0"},{"question":"What is a GPG-signed tag?","answer":"An annotated tag signed with a GPG key for cryptographic verification of authenticity."},{"question":"How do you list all tags matching a pattern?","answer":"git tag -l \"v1.*\""},{"question":"Can tags be moved?","answer":"Technically yes (git tag -f) but tags should be treated as immutable. Avoid moving release tags."},{"question":"What happens when you checkout a tag?","answer":"You enter detached HEAD state. To make changes create a branch from the tag."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Tags</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit A</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Base code</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit B</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Bug fixes</text><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit C</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Features</text><line x1=\"50\" y1=\"90\" x2=\"50\" y2=\"100\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"80\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"220\" y=\"96\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tag: v1.0</text><text x=\"220\" y=\"108\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Annotated release tag</text><rect x=\"10\" y=\"110\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"126\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit D</text><text x=\"65\" y=\"138\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Hotfix</text><line x1=\"50\" y1=\"135\" x2=\"50\" y2=\"145\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"170\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"220\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tag: v1.0.1</text><text x=\"220\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Patch release</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Tags</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Immutable markers on commits. Annotated tags for releases. Semantic versioning.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Tags: Mark release points. Annotated tags for releases. Semantic versioning. GPG signing for authenticity.</text></svg>","codeExamples":[{"title":"Creating and Managing Tags","useCase":"Annotated and lightweight tags.","code":"# Lightweight tag (just a pointer)\ngit tag v1.0-light\n\n# Annotated tag (recommended)\ngit tag -a v1.0 -m \"Release version 1.0\"\n\n# Annotated tag with GPG signature\ngit tag -s v1.0 -m \"Release v1.0 signed\"\n\n# Tag a specific commit (not HEAD)\ngit tag -a v1.0-rc1 a1b2c3d -m \"RC 1\"\n\n# Push a specific tag\ngit push origin v1.0\n\n# Push all tags\ngit push origin --tags\n\n# Verify GPG signature on tag\ngit tag -v v1.0","description":"Create push and verify tags. Always use annotated tags for releases."},{"title":"Semantic Versioning with Tags","useCase":"SemVer convention for tags.","code":"# Semantic versioning format\n# MAJOR.MINOR.PATCH (e.g. v2.1.3)\n\n# MAJOR: breaking changes\ngit tag -a v2.0.0 -m \"Breaking: restructured API\"\n\n# MINOR: new features (backward compatible)\ngit tag -a v1.1.0 -m \"Feat: add search functionality\"\n\n# PATCH: bug fixes (backward compatible)\ngit tag -a v1.0.1 -m \"Fix: resolve memory leak\"\n\n# Pre-release suffix\ngit tag -a v2.0.0-beta.1 -m \"Beta release\"\ngit tag -a v2.0.0-rc.1 -m \"Release candidate\"\n\n# Get current version from tags\ngit describe --tags --abbrev=0\n# v2.1.3","description":"Semantic versioning with tags: MAJOR.MINOR.PATCH with pre-release suffixes."},{"title":"Tags in CI/CD Pipeline","useCase":"Automated release on tag push.","code":"# GitHub Actions: release on tag push\nname: Release\non:\n  push:\n    tags:\n      - \"v*\"\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - name: Extract version from tag\n        run: echo \"VERSION=${GITHUB_REF#refs/tags/}\" >> $GITHUB_ENV\n      - name: Build and publish\n        run: |\n          npm version from-git --no-git-tag-version\n          npm publish","description":"CI/CD pipeline triggered by tag pushes for automated releases."},{"title":"Auto-Tagging in CI","useCase":"Automatically create release tags.","code":"# Auto-create tag after release merge\n#!/bin/bash\n# Get current version from package.json\nVERSION=$(node -p \"require('./package.json').version\")\n\n# Check if tag already exists\nif git rev-parse \"v$VERSION\" >/dev/null 2>&1; then\n  echo \"Tag v$VERSION already exists\"\nelse\n  git tag -a \"v$VERSION\" -m \"Release v$VERSION\"\n  git push origin \"v$VERSION\"\nfi\n\n# GitHub Actions: auto-tag on main merge\n# - run: if git merge-base --is-ancestor HEAD origin/main; then\n#         ./scripts/auto-tag.sh\n#       fi","description":"Automated tag creation from package version during CI."},{"title":"Tag-Based Versioning with Git Describe","useCase":"Get current version from tags.","code":"# git describe generates a human-readable version\ngit describe --tags\n# v1.0-5-gabc1234\n# ^tag  ^commits since tag  ^current commit\n\n# Without commit suffix (nearest tag)\ngit describe --tags --abbrev=0\n# v1.0\n\n# With --match for specific patterns\ngit describe --tags --match \"v[0-9]*\"\n# v1.0-5-gabc1234\n\n# In Node.js for versioning\nconst { execSync } = require('child_process');\nconst version = execSync('git describe --tags --abbrev=0')\n  .toString().trim();\nconsole.log(version); // v1.0","description":"Git describe generates a unique version string from tags and commit count."}],"mcqQuestions":[{"question":"What is a Git tag?","options":["A branch that moves","A reference to a specific commit","A type of merge","A remote URL"],"answer":1,"explanation":"A tag is an immutable reference pointing to a specific commit."},{"question":"What is the difference between lightweight and annotated tags?","options":["Lightweight has metadata","Annotated has author date message","Lightweight is signed","No difference"],"answer":1,"explanation":"Annotated tags store metadata (message tagger date) and can be signed."},{"question":"How do you create an annotated tag?","options":["git tag v1.0","git tag -a v1.0 -m \"message\"","git tag --annotate v1.0","git tag -m v1.0"],"answer":1,"explanation":"Use git tag -a for annotated tags."},{"question":"How do you push a tag to remote?","options":["git push","git push origin v1.0","Tags auto-push","git push --all"],"answer":1,"explanation":"Tags must be explicitly pushed: git push origin <tag-name>."},{"question":"What command lists all tags?","options":["git branch","git tag","git list","git show-tags"],"answer":1,"explanation":"git tag lists all tags. Use -l for pattern matching."},{"question":"What is the recommended tag format for releases?","options":["v1.0 (annotated)","release-1 (lightweight)","R1.0","just \"1\""],"answer":0,"explanation":"Use annotated tags with semantic versioning format (v1.2.3)."},{"question":"Git Tags — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Tags — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Tags — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Tags — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-submodule"] = {"id":"git-submodule","title":"Git Submodules","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Git submodules allow you to include one Git repository as a subdirectory of another Git repository while keeping their histories separate.","Useful for: shared libraries common components external dependencies you manage or splitting a monolith while maintaining connections.","Submodules track a specific commit in the external repo not a branch. The parent repo pins the submodule version (detached HEAD in submodule).","Challenges: complexity of updates need to manually track submodule commits cloning requires --recurse-submodules switching branches can be tricky."],"laymanDefinition":"Git submodules are like a bookshelf in your house. Your house (parent repo) has a designated spot for a specific book (submodule). The book is a separate entity with its own edition author and content. The bookshelf just says I expect the 3rd edition here. If someone updates the book you must consciously decide to update your shelf reference.","deepDive":[{"heading":"How Submodules Work","text":"Parent repo stores a reference (commit SHA) to the submodule repo in .gitmodules and .git/config. git submodule update checks out the pinned commit in the submodule directory. Submodule is in detached HEAD state. Changes to submodule must be committed separately in both repos."},{"heading":"Adding and Cloning Submodules","text":"Add: git submodule add https://github.com/user/lib.git lib/. Cloning a project with submodules: git clone --recurse-submodules <url>. If already cloned: git submodule update --init --recursive. The --recursive flag handles nested submodules."},{"heading":"Updating Submodules","text":"Pull latest from submodule remote branch: cd lib && git pull origin main. Then commit the new submodule reference in parent repo. Or: git submodule update --remote [submodule-name] fetches latest commit from the branch specified in .gitmodules. Always commit the parent reference update."},{"heading":"Submodule Workflows","text":"Consuming: use submodules at fixed versions update intentionally. Contributing: fork submodule make changes push update parent reference. Developing together: work on parent and submodule simultaneously using --recurse-submodules for git commands. Status: git submodule status shows pinned commit."},{"heading":"Submodule Alternatives","text":"Package managers: npm pip Maven (better for most dependencies). Git subtree: merges external repo into your repo (no detached HEAD). Git worktree: multiple working directories of same repo. Monorepo: single repo for all code. For most modern projects package managers are preferred over submodules."}],"interviewAnswer":"Use submodules sparingly. For most dependencies use a package manager. Submodules add complexity: detached HEAD manual updates clone friction. If you use them document the workflow use --recurse-submodules in CI and consider Git subtree as a simpler alternative for tightly coupled projects.","interviewQuestions":[{"question":"What is a Git submodule?","answer":"A reference to another Git repository embedded as a subdirectory keeping the histories independent."},{"question":"How does a parent repo track a submodule?","answer":"By storing a specific commit SHA of the submodule repo. The submodule is at a pinned version."},{"question":"How do you clone a repo with submodules?","answer":"git clone --recurse-submodules <url> or git clone then git submodule update --init --recursive."},{"question":"How do you update a submodule to latest?","answer":"cd submodule && git pull origin main then commit the updated reference in the parent repo."},{"question":"What state is a submodule in?","answer":"Detached HEAD it checks out the pinned commit not a branch."},{"question":"What is .gitmodules?","answer":"A file in the parent repo that stores the mapping of submodule paths to URLs."},{"question":"What is the difference between submodule and subtree?","answer":"Submodule: separate repo reference. Subtree: merges external code into your repo (no external reference needed)."},{"question":"How do you add a submodule?","answer":"git submodule add <repository-url> <path>"},{"question":"Does git submodule update --remote follow a branch?","answer":"Yes it pulls the latest commit from the branch specified in .gitmodules (default: main/master)."},{"question":"What is a common submodule pitfall?","answer":"Forgetting to push the submodule changes before pushing the parent reference update breaking the parent for others."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Submodules</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Parent Repo</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Your application</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Submodule</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">External library</text><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">.gitmodules</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">URL + path mapping</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pinned Commit</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">abc123def456</text><rect x=\"10\" y=\"140\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Update</text><text x=\"65\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New commit ref</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Submodules</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Embed external repos as subdirectories. Separate histories. Pinned commits.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Submodules: Embed external repos at pinned commits. Useful for shared libraries complex dependencies.</text></svg>","codeExamples":[{"title":"Adding and Cloning Submodules","useCase":"Basic submodule operations.","code":"# Add a submodule\ngit submodule add https://github.com/company/utils.git src/utils\n# Creates .gitmodules and clones src/utils\n\n# Check .gitmodules contents\ncat .gitmodules\n# [submodule \"src/utils\"]\n#   path = src/utils\n#   url = https://github.com/company/utils.git\n\n# Clone a project with submodules\ngit clone --recurse-submodules https://github.com/company/app.git\n\n# If you already cloned without --recurse-submodules\ngit submodule update --init --recursive","description":"Adding a submodule and cloning projects that use submodules."},{"title":"Updating Submodules","useCase":"Pull latest from submodule.","code":"# Method 1: manual update\ncd src/utils\ngit checkout main\ngit pull origin main\ncd ../..\ngit add src/utils\ngit commit -m \"chore: update utils submodule\"\n\n# Method 2: automatic update\ngit submodule update --remote src/utils\n# Fetches latest from branch in .gitmodules\ngit add src/utils\ngit commit -m \"chore: update utils submodule\"\n\n# Update all submodules at once\ngit submodule update --remote\ngit add .\ngit commit -m \"chore: update all submodules\"","description":"Update submodules to their latest commits using manual or --remote approach."},{"title":"Working on Submodule Changes","useCase":"Develop and push submodule changes.","code":"# Work on parent and submodule together\n# Start: parent depends on old commit in utils\n\ncd src/utils\ngit checkout main\ngit pull origin main\n\n# Make changes in submodule\necho \"function newFeature() {}\" >> index.js\ngit add .\ngit commit -m \"feat: add newFeature\"\ngit push origin main\n\n# Go back to parent\ncd ../..\ngit add src/utils\ngit commit -m \"feat: integrate newFeature from utils\"\n\n# IMPORTANT: push parent AFTER submodule push\n# Otherwise others get broken parent reference","description":"Workflow for developing submodule and updating parent reference."},{"title":"Submodule in CI/CD","useCase":"Handle submodules in pipelines.","code":"# GitHub Actions with submodules\nname: CI\non: [push]\njobs:\n  test:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n        with:\n          submodules: recursive\n          token: ${{ secrets.GH_PAT }}\n      - run: npm ci\n      - run: npm test\n\n# For private submodules use PAT or SSH key:\n# - uses: actions/checkout@v3\n#   with:\n#     submodules: recursive\n#     ssh-key: ${{ secrets.SSH_PRIVATE_KEY }}","description":"CI/CD pipeline configuration for repositories with submodules."},{"title":"Submodule Branch Tracking","useCase":"Follow a specific branch.","code":"# Configure submodule to track a branch\ngit config -f .gitmodules submodule.src/utils.branch main\n\n# Or during initial add:\ngit submodule add -b main https://github.com/company/utils.git src/utils\n\n# Now update --remote follows the branch\ngit submodule update --remote src/utils\n# Fetches latest commit on main branch\n\n# .gitmodules will have:\n# [submodule \"src/utils\"]\n#   path = src/utils\n#   url = https://github.com/company/utils.git\n#   branch = main","description":"Configure submodules to track a branch for automatic updates with --remote."}],"mcqQuestions":[{"question":"What is a Git submodule?","options":["A built-in Git library","An embedded repo reference","A Git command alias","A remote backup"],"answer":1,"explanation":"A submodule embeds another Git repository at a pinned commit."},{"question":"How does a parent repo track a submodule?","options":["By branch name","By commit SHA","By tag name","By file content hash"],"answer":1,"explanation":"The parent repo stores the specific commit SHA of the submodule."},{"question":"How do you clone a repo with submodules?","options":["git clone --recursive","git clone --all","git clone --deep","git clone --full"],"answer":0,"explanation":"Use git clone --recurse-submodules or git submodule update --init after cloning."},{"question":"What state is a submodule checked out to?","options":["On main branch","Detached HEAD","On develop branch","On a tag"],"answer":1,"explanation":"Submodules are checked out in detached HEAD state at the pinned commit."},{"question":"What file stores submodule configuration?","options":[".gitignore",".gitmodules",".gitattributes","package.json"],"answer":1,"explanation":".gitmodules stores the URL and path mapping for submodules."},{"question":"What is the main risk with submodules?","options":["Security vulnerabilities","Out-of-sync references breaking builds","Slow performance","Disk space usage"],"answer":1,"explanation":"If submodule changes are pushed before the parent updates its reference others get broken builds."},{"question":"Git Submodules — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Submodules — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Submodules — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Submodules — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-hooks"] = {"id":"git-hooks","title":"Git Hooks","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Git hooks are custom scripts that run automatically at specific points in the Git lifecycle (commit push merge etc.).","Client-side hooks: pre-commit pre-push post-commit post-merge (run on developer machine). Server-side hooks: pre-receive post-receive update (run on remote repository).","Typical uses: lint checking before commits test running before push commit message validation code formatting preventing secrets in code.","Hooks are stored in .git/hooks/ but are not tracked by Git (not part of repository). Use tools like Husky to manage and share hooks with the team."],"laymanDefinition":"Git hooks are like airport security checkpoints. Before your commit can board (be saved) it must pass through pre-commit security: luggage check (linting) ID verification (author check) and ticket validation (message format). Pre-push is the final boarding gate: all tests must pass before takeoff.","deepDive":[{"heading":"Client-Side Hook Types","text":"pre-commit: runs before commit message is created. Can abort commit. prepare-commit-msg: runs before editor opens for commit message. commit-msg: runs after message is written (validate format). post-commit: runs after commit (notifications). pre-push: runs before push (tests). post-merge: after merge (install new deps)."},{"heading":"Server-Side Hook Types","text":"pre-receive: runs on remote when push is received. Can reject entire push. update: runs for each branch being pushed. Can reject specific branches. post-receive: runs after push is accepted (CI trigger deploy notifications). Used for policy enforcement code review gates deployment triggers."},{"heading":"Pre-Commit Hook Pattern","text":"Typically: stash unstaged changes to run linters/formatters on staged files to check for issues to if issues abort with message to restore unstaged changes. Tools: lint-staged runs linters only on staged files. Pre-commit frameworks: husky + lint-staged is the modern standard for Node.js."},{"heading":"Commit Message Hooks","text":"commit-msg hook validates message format. Enforce: conventional commits (type(scope): message) max line length (72 chars) no WIP ticket reference required. Pattern matching: if [[ ! \"$MSG\" =~ ^(feat|fix|docs|chore): ]] to reject. Great for maintaining clean commit history."},{"heading":"Sharing Hooks with the Team","text":"Hooks are in .git/hooks/ (not tracked). Solution: store hooks in .githooks/ directory. Configure core.hooksPath: git config core.hooksPath .githooks. Or use Husky: manages hooks via package.json scripts auto-installs on npm install. For polyglot projects: scripts/hooks/ directory with README or install script."}],"interviewAnswer":"Git hooks automate quality checks and enforce team conventions. Use Husky + lint-staged for client-side hooks. Start with pre-commit (linting) and pre-push (tests). Validate commit messages with commit-msg hook. Server-side hooks enforce policies. Keep hooks fast slow hooks frustrate developers.","interviewQuestions":[{"question":"What are Git hooks?","answer":"Custom scripts that run automatically at specific Git lifecycle events (commit push merge)."},{"question":"Where are hooks stored?","answer":"In .git/hooks/ (local not tracked by Git). Can be configured via core.hooksPath."},{"question":"What is a pre-commit hook used for?","answer":"Running linters formatters and checks before a commit is created. Can abort on failure."},{"question":"What is a pre-push hook used for?","answer":"Running tests builds or security scans before pushing to remote."},{"question":"How do you share hooks with the team?","answer":"Use Husky (npm) store hooks in .githooks/ directory or use a hooks management tool."},{"question":"What is the commit-msg hook?","answer":"Validates the commit message format (length conventional commit compliance ticket reference)."},{"question":"What are server-side hooks?","answer":"pre-receive update post-receive run on the remote repository during push."},{"question":"What is the post-receive hook used for?","answer":"CI/CD triggers deployment notifications after a push is accepted."},{"question":"What is Husky?","answer":"A modern tool for managing Git hooks via package.json that auto-installs hooks on npm install."},{"question":"What is the danger of slow hooks?","answer":"Developers may bypass hooks (git commit --no-verify). Keep hooks fast (<1 second)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Hooks</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">pre-commit</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Lint + format</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">commit-msg</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Validate message</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">post-commit</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Notification</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">pre-push</text><text x=\"215\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Run tests</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">post-merge</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Install deps</text><rect x=\"10\" y=\"140\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"65\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Server Hooks</text><text x=\"65\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Policy + deploy</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Hooks</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated scripts at Git lifecycle events. Quality gates formatting validation.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Hooks: Automated scripts at commit/push/merge events. Enforce quality conventions and policies.</text></svg>","codeExamples":[{"title":"Pre-Commit Hook with Husky + lint-staged","useCase":"Modern lint-on-commit setup.","code":"# package.json\n# Install: npm install --save-dev husky lint-staged\n\n{\n  \"scripts\": {\n    \"prepare\": \"husky install\"\n  },\n  \"lint-staged\": {\n    \"*.{js ts}\": [\"eslint --fix\" \"prettier --write\"],\n    \"*.md\": [\"prettier --write\"]\n  },\n  \"devDependencies\": {\n    \"husky\": \"^8.0.0\",\n    \"lint-staged\": \"^13.0.0\"\n  }\n}\n\n# Create hook:\n# npx husky add .husky/pre-commit \"npx lint-staged\"\n\n# .husky/pre-commit:\n#!/usr/bin/env sh\n. \"$(dirname \"$0\")/_/husky.sh\"\n\nnpx lint-staged","description":"Husky + lint-staged setup: auto-format and lint only staged files on commit."},{"title":"Pre-Push Hook (Run Tests)","useCase":"Prevent pushing broken code.","code":"#!/bin/bash\n# .husky/pre-push\n\necho \"Running tests before push...\"\n\nnpm test\nif [ $? -ne 0 ]; then\n  echo \"Tests failed. Push aborted.\"\n  exit 1\nfi\n\necho \"All tests passed. Push allowed.\"\n\n# To bypass: git push --no-verify\n# Use sparingly only in emergencies","description":"Pre-push hook runs tests and aborts the push if tests fail."},{"title":"Commit Message Validation","useCase":"Enforce conventional commits.","code":"#!/bin/bash\n# .husky/commit-msg\n\nMSG_FILE=$1\nMSG=$(cat \"$MSG_FILE\")\n\n# Conventional commit pattern\nPATTERN=\"^(feat|fix|docs|style|refactor|test|chore|ci)(\\\\(.+\\\\))?: .+\"\n\nif [[ ! \"$MSG\" =~ $PATTERN ]]; then\n  echo \"Error: Invalid commit message format\"\n  echo \"Must match: type(scope): description\"\n  echo \"Types: feat fix docs style refactor test chore ci\"\n  echo \"Example: feat(login): add OAuth support\"\n  exit 1\nfi\n\n# Check line length\nMSG_LENGTH=$(echo \"$MSG\" | wc -c)\nif [ \"$MSG_LENGTH\" -gt 72 ]; then\n  echo \"Error: Commit message too long (>72 chars)\"\n  exit 1\nfi","description":"Enforce conventional commit format and line length with commit-msg hook."},{"title":"Prevent Secrets in Commits","useCase":"Block secrets from being committed.","code":"#!/bin/bash\n# .husky/pre-commit prevent secrets\n\n# Check for common secret patterns\nSECRET_PATTERNS=(\n  \"AKIA[0-9A-Z]{16}\"  # AWS access key\n  \"ghp_[a-zA-Z0-9]{36}\"  # GitHub PAT\n  \"-----BEGIN.*PRIVATE KEY-----\"  # Private key\n  \"sk_live_[a-zA-Z0-9]+\"  # Stripe live key\n  \"xox[barp]-[a-zA-Z0-9-]+\"  # Slack token\n)\n\nFILES=$(git diff --cached --name-only | grep -v '^\\.env\\.example$')\n\nfor PATTERN in \"${SECRET_PATTERNS[@]}\"; do\n  if git diff --cached -G\"$PATTERN\" -- \"$FILES\" | grep -q \"$PATTERN\"; then\n    echo \"Error: Potential secret detected in staged files!\"\n    echo \"Pattern: $PATTERN\"\n    exit 1\n  fi\ndone","description":"Pre-commit hook scans staged files for API keys tokens and private keys."},{"title":"Post-Merge Hook (Install Dependencies)","useCase":"Auto-install after pull.","code":"#!/bin/bash\n# .husky/post-merge\n\n# Check if package.json changed\nCHANGED=$(git diff HEAD@{1} HEAD --name-only)\n\nif echo \"$CHANGED\" | grep -q \"package.json\"; then\n  echo \"package.json changed installing dependencies\"\n  npm install\nfi\n\nif echo \"$CHANGED\" | grep -q \"composer.json\"; then\n  composer install\nfi\n\nif echo \"$CHANGED\" | grep -q \"Gemfile\"; then\n  bundle install\nfi","description":"Post-merge hook detects dependency file changes and auto-installs."}],"mcqQuestions":[{"question":"What are Git hooks?","options":["Git configuration files","Scripts that run at Git events","Git command aliases","Remote repository settings"],"answer":1,"explanation":"Git hooks are scripts triggered by Git lifecycle events."},{"question":"Where are hooks stored locally?","options":["In the repository root","In .git/hooks/","In node_modules/","In GitHub settings"],"answer":1,"explanation":"Hooks are in .git/hooks/ (not tracked by Git)."},{"question":"What is the most common pre-commit use?","options":["Deploy to production","Run linters on staged files","Create a new branch","Delete remote branches"],"answer":1,"explanation":"Pre-commit hooks typically run linters and formatters on staged changes."},{"question":"What tool manages hooks via package.json?","options":["npm","Husky","Webpack","Babel"],"answer":1,"explanation":"Husky manages Git hooks through package.json configuration."},{"question":"How do you bypass hooks?","options":["git commit --force","git commit --no-verify","git commit --skip-hooks","Cannot bypass"],"answer":1,"explanation":"Use --no-verify (or -n) to bypass client-side hooks temporarily."},{"question":"What hook validates commit messages?","options":["pre-commit","commit-msg","prepare-commit-msg","post-commit"],"answer":1,"explanation":"The commit-msg hook validates the commit message after it is written."},{"question":"Git Hooks — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Hooks — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Hooks — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Hooks — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-bisect"] = {"id":"git-bisect","title":"Git Bisect","difficulty":"advanced","estimatedMinutes":15,"tldr":["Git bisect uses binary search to find the specific commit that introduced a bug. It automates the good/bad testing process.","You mark a known good commit (before bug) and a known bad commit (after bug). Bisect checks out commits in the middle for you to test.","Each step: test the current commit (manually or with a script) mark git bisect good or bad. Bisect narrows down until it finds the first bad commit.","Automated: git bisect run <script> runs a script at each step and uses exit code (0 = good 1-127 = bad 125 = skip) to determine result."],"laymanDefinition":"Git bisect is like finding the day your fridge broke by halving your calendar. You know the fridge worked on Jan 1 (good) and it is broken today (bad). Check halfway: Jan 15. If working good half is eliminated. Check Mar 1. If broken bad half. In ~4 steps you find the exact day without checking every single day.","deepDive":[{"heading":"Binary Search Algorithm","text":"Bisect uses true binary search O(log n). 1000 commits to ~10 steps. 10000 commits to ~14 steps. Start: mark one commit good one bad. Git checks out the midpoint. You test and mark good/bad. Bisect halves the range each iteration. It converges to the exact commit that introduced the bug."},{"heading":"Manual Bisect Workflow","text":"git bisect start to git bisect good <sha> to git bisect bad <sha> to git checks out midpoint to test to git bisect good/bad to repeat to git bisect reset when done. Visualize progress: git bisect visualize shows the remaining commit range in gitk/log."},{"heading":"Automated Bisect (git bisect run)","text":"Script must return exit code 0 (good) or non-zero (bad) 125 (cannot test skip). Example: git bisect run npm test. Or: git bisect run ./test.sh. The script should be deterministic and quick. Automating bisect makes finding the bad commit effortless."},{"heading":"Bisect Strategies","text":"Wide range first: mark exact boundaries if known. Step size: bisect automatically computes. Skip commits that cannot be tested: git bisect skip (or exit 125 in script). Resume: git bisect replay <logfile>. Visualize: git bisect log for audit trail."},{"heading":"Bisect with Fixed Bug","text":"If the bad commit cannot be reproduced (flakey test environment-specific) bisect may give false positives. Best practices: write a deterministic test script. Run the script multiple times at the found commit to confirm. Check merge commits: bisect may point to a merge if the bug entered via merge."}],"interviewAnswer":"Git bisect is the most efficient tool for finding the source of a bug. Automate with git bisect run and a test script. Start with a wide range and narrow down. Always git bisect reset when done. For flakey tests mark 125 to skip. Bisect is invaluable for regression debugging.","interviewQuestions":[{"question":"What is git bisect?","answer":"A binary search tool to find the commit that introduced a bug."},{"question":"How does bisect work?","answer":"Mark a good commit (before bug) and a bad commit (after bug). Git binary searches by checking out midpoints."},{"question":"How many steps for 1000 commits?","answer":"About 10 steps (log2(1000) ~ 10)."},{"question":"What does git bisect run do?","answer":"Automates bisect with a script. Exit code 0 = good non-zero = bad 125 = skip."},{"question":"How do you exit bisect?","answer":"git bisect reset. Returns HEAD to the original position."},{"question":"What does exit code 125 mean in bisect run?","answer":"Cannot test this commit (skip it). Used for flakey tests or broken builds."},{"question":"Can bisect skip commits?","answer":"Yes: git bisect skip or exit 125 in automated run."},{"question":"How do you see bisect progress?","answer":"git bisect visualize shows remaining commits in gitk. git bisect log shows the full bisect history."},{"question":"What happens when bisect finds multiple commits?","answer":"Bisect finds the first bad commit. If there are multiple bad commits in sequence it finds the first one."},{"question":"What is a skip strategy in bisect?","answer":"If a commit cannot be built/tested skip it. Bisect will choose a different commit in the range."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Bisect</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Good</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">v1.0 (works)</text><line x1=\"110\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"140\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"190\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Midpoint</text><text x=\"190\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Test here</text><line x1=\"240\" y1=\"48\" x2=\"260\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"270\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"320\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Bad</text><text x=\"320\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">v1.1 (broken)</text><rect x=\"10\" y=\"70\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"75\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 2</text><text x=\"75\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Narrow range</text><rect x=\"10\" y=\"110\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"75\" y=\"126\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Step 3</text><text x=\"75\" y=\"138\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Further narrow</text><rect x=\"10\" y=\"150\" width=\"130\" height=\"30\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"75\" y=\"166\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Found!</text><text x=\"75\" y=\"178\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">First bad commit</text><rect x=\"160\" y=\"70\" width=\"220\" height=\"30\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Binary Search: O(log n)</text><text x=\"270\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">1000 commits to ~10 steps. Test midpoint each iteration.</text><rect x=\"160\" y=\"115\" width=\"220\" height=\"60\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"270\" y=\"131\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Automated: git bisect run <script></text><text x=\"270\" y=\"143\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Exit 0 = good 1-127 = bad 125 = skip</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Bisect: Binary search for the commit that introduced a bug. Manual or automated with git bisect run.</text></svg>","codeExamples":[{"title":"Manual Bisect Workflow","useCase":"Find bug commit step by step.","code":"# Start bisect\ngit bisect start\n\n# Mark known good and bad\ngit bisect good v1.0\ngit bisect bad HEAD\n# Bisecting: 342 revisions left to test\n\n# Git checks out midpoint test it\n# Test manually...\n\n# If the bug is NOT present:\ngit bisect good\n# Bisecting: 171 revisions left to test\n\n# If the bug IS present:\ngit bisect bad\n# Bisecting: 85 revisions left to test\n\n# Repeat until found:\n# abc123def456 is the first bad commit\n\n# Exit bisect mode\ngit bisect reset","description":"Manual bisect workflow: mark good/bad commits test midpoints bisect finds the first bad commit."},{"title":"Automated Bisect with Test Script","useCase":"Let bisect run tests automatically.","code":"# Create a test script (test-bug.sh)\n#!/bin/bash\nnpm ci --silent\nnpx playwright test tests/login.spec.js\n# Exit code: 0 = good (bug fixed) non-zero = bad (bug present)\n\n# Make executable\nchmod +x test-bug.sh\n\n# Run automated bisect\ngit bisect start\ngit bisect good v1.0\ngit bisect bad HEAD\ngit bisect run ./test-bug.sh\n\n# Bisect runs the script at each commit\n# Output:\n# running ./test-bug.sh\n# ... test output ...\n# abc123def456 is the first bad commit\n\ngit bisect reset","description":"Automated bisect with git bisect run executes a test script at each commit."},{"title":"Skip Unbuildable Commits","useCase":"Handle commits that cannot be tested.","code":"#!/bin/bash\n# test-with-skip.sh exit 125 for unbuildable commits\n\nif ! npm ci --silent 2>/dev/null; then\n  echo \"Dependencies cannot be installed skipping\"\n  exit 125  # tell bisect to skip this commit\nfi\n\nif ! npm run build 2>/dev/null; then\n  echo \"Build failed skipping\"\n  exit 125\nfi\n\nnpm test\n# exit code 0 = good non-zero = bad\n\n# Run bisect with skip-aware script\ngit bisect start HEAD v1.0\ngit bisect run ./test-with-skip.sh","description":"Use exit 125 to skip commits that cannot be built or tested."},{"title":"Bisect with Merge Commits","useCase":"Handle merge commits in bisect.","code":"# Bisect can point to merge commits\n# Use --first-parent to avoid merge islands\n\n# Bisect following only first parent\ngit bisect start --first-parent\ngit bisect good v1.0\ngit bisect bad HEAD\n\n# Or skip merge commits manually\ngit bisect skip\n\n# Verify the found commit:\ngit show <bad-commit> --stat\ngit log --oneline <bad-commit>~1..<bad-commit>\n\n# Check if the bug was introduced by a merge:\ngit log --first-parent <bad-commit>~1..<bad-commit>","description":"--first-parent avoids bisecting into merged branches keeping the search linear."},{"title":"Bisect Log and Replay","useCase":"Save and restore bisect state.","code":"# Save the current bisect session\ngit bisect log > bisect-log.txt\n\n# Later (or on another machine) replay it\ngit bisect replay bisect-log.txt\n# Re-executes all the good/bad marks\n\n# View bisect state\ngit bisect visualize\n# Shows remaining commits in gitk\n\n# Check bisect status\ngit bisect status\n# Shows current bisect state","description":"Bisect log/replay allows saving and sharing bisect sessions for collaboration."}],"mcqQuestions":[{"question":"What algorithm does git bisect use?","options":["Linear search","Binary search","Hash lookup","Bubble sort"],"answer":1,"explanation":"Git bisect uses binary search (O(log n)) to find the first bad commit."},{"question":"How many bisect steps for ~1000 commits?","options":["~100","~50","~10","~3"],"answer":2,"explanation":"log2(1000) ~ 10 steps. Binary search halves the range each time."},{"question":"How do you automate bisect?","options":["git bisect auto","git bisect run <script>","git bisect auto-run","git bisect go"],"answer":1,"explanation":"git bisect run automates bisect using a test script."},{"question":"What does exit code 125 mean in bisect run?","options":["Good commit","Bad commit","Skip this commit","Abort bisect"],"answer":2,"explanation":"Exit 125 tells git bisect to skip the current commit (cannot test)."},{"question":"How do you exit bisect mode?","options":["git bisect end","git bisect reset","git bisect stop","git bisect quit"],"answer":1,"explanation":"git bisect reset exits bisect and returns HEAD to its original position."},{"question":"What is the benefit of bisect over manual searching?","options":["Easier to type","Logarithmically fewer steps","More accurate","Works offline"],"answer":1,"explanation":"Bisect finds the bad commit in O(log n) steps instead of O(n)."},{"question":"Git Bisect — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Bisect — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Bisect — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Bisect — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-revert"] = {"id":"git-revert","title":"Git Revert","difficulty":"intermediate","estimatedMinutes":10,"tldr":["Git revert creates a new commit that undoes the changes from a previous commit. The history remains intact no rewriting.","Unlike git reset (moves branch pointer rewrites history) revert is safe for shared branches because it adds a new commit rather than deleting history.","Revert a single commit: git revert <sha>. Revert a range: git revert <old>..<new>. Revert a merge: git revert -m 1 <merge-sha>.","Revert is the recommended way to undo changes on public/shared branches. It preserves the full commit history and is safe for collaboration."],"laymanDefinition":"Git revert is like a time machine that adds a new event to undo a past event rather than erasing the past. If you baked a cake (commit) and it turns out terrible revert adds a remove cake from kitchen event to the timeline. The original bake cake event is still in the history you can see it. Reset would be erasing the memory of baking entirely.","deepDive":[{"heading":"How Revert Works","text":"Revert computes the inverse diff of the target commit and applies it as a new commit. If commit A added 10 lines revert A creates a commit that removes those 10 lines. If commit A removed a file revert A restores it (if no conflicting changes). The original commit remains in history."},{"heading":"Reverting a Single Commit","text":"git revert <sha>. Opens editor for commit message (default: \"Revert <commit-title>\"). Works on any commit not just HEAD. No-edit: git revert --no-edit <sha>. No-commit: git revert -n <sha> (stage changes but don commit allows combining multiple reverts)."},{"heading":"Reverting a Merge Commit","text":"Merge commits have two parents. git revert -m 1 <merge-sha> reverts to the state of parent 1 (the branch you were on). -m 2 reverts to parent 2 (the branch you merged). Without -m git refuses to revert a merge (ambiguous)."},{"heading":"Revert Conflicts","text":"If later commits modified the same code revert may conflict. Resolution is like a normal merge conflict: edit git add git revert --continue. Or abort: git revert --abort. To skip a conflicted revert: git revert --skip."},{"heading":"Revert vs Reset vs Restore","text":"Revert: safe for public history creates new commit. Reset: moves branch pointer rewrites history (use only on local/unpushed branches). Restore: restores working tree/index files (new Git 2.23+). For public/shared branches always use revert."}],"interviewAnswer":"Use revert for undoing changes on shared branches it preserves history and is safe for collaboration. Revert works by creating a new commit that undoes the target commit. Handle revert of merge commits with -m to specify the parent. Revert conflicts resolve like normal conflicts. Never use reset on public branches.","interviewQuestions":[{"question":"What is git revert?","answer":"Creates a new commit that undoes the changes from a previous commit. History is preserved."},{"question":"How does revert differ from reset?","answer":"Revert: new commit safe for shared branches. Reset: moves branch pointer rewrites history."},{"question":"How do you revert a specific commit?","answer":"git revert <commit-sha>. Opens editor for commit message."},{"question":"How do you revert a merge commit?","answer":"git revert -m 1 <merge-sha>. -m specifies which parent to revert to."},{"question":"Can revert cause conflicts?","answer":"Yes if later commits modified the same code. Resolve like a normal conflict."},{"question":"How do you abort a revert?","answer":"git revert --abort. Returns to pre-revert state."},{"question":"What is the default revert commit message?","answer":"\"Revert <original commit title>\". The original commit is referenced by SHA."},{"question":"How do you revert without opening an editor?","answer":"git revert --no-edit <sha>. Uses the default revert message."},{"question":"Can you revert multiple commits at once?","answer":"Yes: git revert --no-commit <old>..<new> then commit once. Or revert each individually."},{"question":"Why should you use revert instead of reset on public branches?","answer":"Revert is safe for collaboration (adds history). Reset rewrites history breaking other developers repositories."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Revert</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit A</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Original change</text><line x1=\"110\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"140\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"190\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit B</text><text x=\"190\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">More changes</text><line x1=\"240\" y1=\"48\" x2=\"260\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Revert A</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">UNDO commit A</text><rect x=\"10\" y=\"100\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Commit C</text><text x=\"60\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New revert commit</text><rect x=\"10\" y=\"130\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Safe</text><text x=\"60\" y=\"158\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">History unchanged</text><rect x=\"140\" y=\"70\" width=\"250\" height=\"100\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"265\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Revert</text><text x=\"265\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Creates a new commit that undoes a previous commit. Safe for shared branches.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Revert: Undo past commits safely by creating a new inverse commit. Preserves full history.</text></svg>","codeExamples":[{"title":"Basic Revert Commands","useCase":"Undo commits safely.","code":"# Revert a single commit\ngit log --oneline -5\n# a1b2c3d Add login form\n# e4f5g6h Fix login validation\n\ngit revert a1b2c3d\n# Opens editor: Revert \"Add login form\"\n# Creates new commit undoing a1b2c3d\n\n# Revert without editing message\ngit revert --no-edit a1b2c3d\n\n# Revert but do not commit (stage changes)\ngit revert -n a1b2c3d\n# Make additional changes then commit\ngit commit -m \"fix: revert login form and adjust tests\"\n\n# Revert multiple commits (oldest first)\ngit revert --no-edit a1b2c3d e4f5g6h","description":"Basic revert commands for undoing specific commits with various options."},{"title":"Reverting a Merge Commit","useCase":"Safely undo a merge.","code":"# Find the merge commit\ngit log --oneline --merges -5\n# m0n1o2p Merge feature/login into main\n\n# Revert to parent 1 (what main was before merge)\ngit revert -m 1 m0n1o2p --no-edit\n\n# Revert to parent 2 (what feature/login was)\ngit revert -m 2 m0n1o2p\n\n# Why -m is needed:\n# Merge commit has 2 parents:\n# Parent 1: main (the branch you were on)\n# Parent 2: feature/login (the merged branch)\n# -m 1 means undo to main previous state\n\n# After revert you can re-merge later\n# (the reverted merge is still in history)","description":"Revert merge commits using -m to specify which parent to revert to."},{"title":"Revert With Conflicts","useCase":"Resolve conflicts during revert.","code":"# Revert causes conflict\ngit revert a1b2c3d\n# error: could not revert a1b2c3d...\n# hint: after resolving the conflicts\n# hint: mark them with \"git add\"\n\n# Check status to see conflicted files\ngit status\n# both modified: src/auth.js\n\n# Open and resolve conflict\n# Edit file remove >>> <<< markers\n\n# Mark as resolved\ngit add src/auth.js\n\n# Complete revert\ngit revert --continue\n\n# Or abort revert entirely\ngit revert --abort","description":"Handle revert conflicts by resolving files and completing the revert."},{"title":"Revert Already Reverted","useCase":"Re-apply a reverted commit.","code":"# Scenario: you reverted a commit\n# but now want to re-apply it\n\n# Option 1: revert the revert\ngit revert <revert-commit-sha>\n# Creates a commit that re-applies the original\n\n# Option 2: cherry-pick the original commit\ngit cherry-pick <original-commit-sha>\n# Re-applies the original commit on current branch\n\n# Option 3: rebase and drop the revert\n# (only if branch is local/unpushed)\ngit rebase -i HEAD~5\n# Delete the revert commit line","description":"Revert a revert or cherry-pick to re-apply changes that were previously reverted."},{"title":"Revert and Continue (No-Commit)","useCase":"Combine multiple reverts into one commit.","code":"# Stage multiple reverts without committing\ngit revert -n a1b2c3d\ngit revert -n e4f5g6h\ngit revert -n i7j8k9l\n\n# All changes are staged but not committed\ngit status\n# Changes staged: 3 reverts applied\n\n# Combine into a single commit\ngit commit -m \"fix: revert login validation and OAuth changes\"\n\n# Useful for:\n# - Reverting a whole feature\n# - Atomic revert of multiple related commits\n# - Cleaner history than individual revert commits","description":"Use --no-commit (-n) to stage multiple reverts before committing them together."}],"mcqQuestions":[{"question":"What does git revert do?","options":["Deletes a commit","Creates a new commit that undoes changes","Moves branch pointer","Rewrites history"],"answer":1,"explanation":"Revert creates a new inverse commit safe for shared history."},{"question":"How is revert different from reset?","options":["Revert rewrites history","Revert adds a new commit reset moves pointer","They are the same","Reset is safer for shared branches"],"answer":1,"explanation":"Revert adds history (safe) reset rewrites history (unsafe for shared branches)."},{"question":"What flag reverts a merge commit?","options":["-m (parent number)","-p (parent)","--merge","-f (force)"],"answer":0,"explanation":"-m specifies which parent to revert to: -m 1 or -m 2."},{"question":"What happens if a revert causes conflicts?","options":["Revert is automatically aborted","Resolve conflicts and git revert --continue","The commit is skipped","Git force-reverts anyway"],"answer":1,"explanation":"Handle revert conflicts like merge conflicts: resolve add continue."},{"question":"How do you revert without opening an editor?","options":["git revert --silent","git revert --no-edit","git revert --quiet","git revert --auto"],"answer":1,"explanation":"--no-edit uses the default revert message without opening an editor."},{"question":"Why use revert instead of reset on main?","options":["Faster operation","History is preserved for collaboration","Smaller repository size","No conflicts possible"],"answer":1,"explanation":"Revert creates a new commit (preserves history) which is safe for shared branches."},{"question":"Git Revert — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Revert — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Revert — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Revert — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-reset"] = {"id":"git-reset","title":"Git Reset","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Git reset moves the current branch pointer backward or forward to a specific commit optionally modifying the staging area and working directory.","Three modes: --soft (only moves HEAD) --mixed (moves HEAD + resets staging area default) --hard (moves HEAD + resets staging + working directory).","Reset is destructive on uncommitted work (--hard) and on commits no longer referenced (dangling commits can be recovered via reflog).","Use reset for local branch cleanup unstaging files and discarding local changes. Never use reset on shared branches (rewrites history)."],"laymanDefinition":"Git reset is like adjusting a VCR tape to a specific timestamp. --soft is like moving the tape position (HEAD) but leaving the picture (working dir) and loading tray (staging) untouched. --mixed also ejects the tape (unstages). --hard rewinds ejects and forgets everything after that point like it never happened.","deepDive":[{"heading":"Reset Modes","text":"--soft: HEAD now points to target commit. Staging area and working directory are unchanged. All changes from reset point to current state become staged. --mixed (default): HEAD moves staging area matches HEAD working directory unchanged. Changes become unstaged. --hard: HEAD moves staging and working directory match HEAD. Uncommitted changes are lost."},{"heading":"Reset vs Checkout","text":"git reset moves branch pointers. git checkout switches branches (and can restore files). Reset operates on the current branch. Checkout switches to a different branch. Both can restore specific files but have different effects on HEAD. Reset --hard <commit> is the most dangerous it discards working directory changes."},{"heading":"Soft Reset Use Cases","text":"Combine multiple commits into one: git reset --soft HEAD~3 then git commit -m \"Squashed feature\". Uncommit but keep changes staged: git reset --soft HEAD~1. Adjust commit base: reset --soft to a different commit. Safe because working directory is untouched no data loss."},{"heading":"Mixed Reset (Default) Use Cases","text":"Unstage files: git reset (defaults to --mixed HEAD). Uncommit and unstage: git reset --mixed HEAD~1. Unstage selective: git reset HEAD -- filename. Most common reset for everyday use changes remain in working directory."},{"heading":"Hard Reset and Recovery","text":"git reset --hard HEAD~3: discards last 3 commits and all uncommitted changes. DANGEROUS. Recovery: git reflog to find the old HEAD SHA. git reset --hard <sha> to restore. Or git checkout -b recovered <sha> to create a branch. Reflog keeps history for ~90 days (git gc prunes it)."}],"interviewAnswer":"Reset is powerful but dangerous. Use --soft to merge commits. Use --mixed (default) to unstage. Use --hard sparingly. Never reset shared branches. Recovery is possible via reflog but not guaranteed. For undoing shared history use revert. For local changes reset is the right tool.","interviewQuestions":[{"question":"What is git reset?","answer":"Moves the current branch pointer to a specified commit optionally modifying staging and working directory."},{"question":"What are the three reset modes?","answer":"--soft (HEAD only) --mixed (HEAD + staging default) --hard (HEAD + staging + working directory)."},{"question":"What does --soft do?","answer":"Moves HEAD only. Staging and working directory unchanged. Changes become staged."},{"question":"What does --mixed do?","answer":"Moves HEAD and resets staging area. Working directory unchanged. Changes become unstaged. Default mode."},{"question":"What does --hard do?","answer":"Moves HEAD resets staging area and overwrites working directory. Uncommitted changes lost."},{"question":"What is the default reset mode?","answer":"--mixed (if no mode specified)."},{"question":"Can you recover from git reset --hard?","answer":"Yes via git reflog. Find the old HEAD SHA and reset to it."},{"question":"Why should you never reset shared branches?","answer":"Reset rewrites history causing divergence for other developers who have the old history."},{"question":"What is git reset HEAD -- filename?","answer":"Unstages the file (removes from staging area) but keeps working directory changes."},{"question":"How do you uncommit the last commit but keep changes?","answer":"git reset --soft HEAD~1 (keeps changes staged) or git reset HEAD~1 (keeps changes unstaged)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Reset</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Original</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Commit A to B to C (HEAD)</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">--soft</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HEAD to A changes staged</text><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">--mixed</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HEAD to A changes unstaged</text><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">--hard</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HEAD to A changes LOST</text><rect x=\"10\" y=\"140\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Reflog</text><text x=\"65\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Recovery possible</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Reset</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Move branch pointer with 3 modes: --soft --mixed --hard. Dangerous on shared branches.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Reset: Move HEAD pointer. --soft (keep staged) --mixed (unstage) --hard (discard all).</text></svg>","codeExamples":[{"title":"Reset Modes Comparison","useCase":"Visual difference between modes.","code":"# Initial state:\n# Commit A -- Commit B -- Commit C (HEAD)\n# Modified: src/index.js (unstaged)\n# Staged: src/utils.js\n\n# --soft: HEAD to Commit A\ngit reset --soft HEAD~2\n# HEAD to Commit A\n# Staged: src/utils.js + src/index.js\n# Working: src/index.js (modified)\n\n# --mixed (default): HEAD to Commit A\ngit reset --mixed HEAD~1\n# HEAD to Commit B\n# Staged: (empty)\n# Working: src/index.js (modified)\n\n# --hard: HEAD to Commit A\ngit reset --hard HEAD~1\n# HEAD to Commit B\n# Working: clean (index.js changes LOST)","description":"Comparison of --soft --mixed and --hard reset modes."},{"title":"Soft Reset for Squash Commits","useCase":"Combine multiple commits.","code":"# Before: 3 messy commits\ngit log --oneline -5\n# d3f4g5h fix typo\n# b2c3d4e add test\n# a1b2c3d add feature\n\n# Squash into one commit\ngit reset --soft HEAD~3\ngit commit -m \"feat: add login feature with tests\"\n\n# After: 1 clean commit\ngit log --oneline -3\n# x1y2z3w feat: add login feature with tests\n\n# All changes from 3 commits are now in 1 commit\n# Working directory unchanged safe","description":"Soft reset combines multiple commits into one without losing changes."},{"title":"Unstage Files with Mixed Reset","useCase":"Remove files from staging.","code":"# Accidentally staged all files\ngit add .\ngit status\n# Changes staged: 10 files\n\n# Unstage everything (keep changes)\ngit reset\n# Equivalent to: git reset --mixed HEAD\n\n# Unstage specific file\ngit reset HEAD -- src/config.js\n\n# Now config.js changes are unstaged\n# but still in working directory\n\n# Uncommit last commit but keep changes\ngit reset HEAD~1\n# HEAD moves back 1 changes are unstaged\n# Ready to re-commit with corrections","description":"Mixed reset unstages files while keeping working directory changes intact."},{"title":"Recover from Hard Reset","useCase":"Find lost commits via reflog.","code":"# DANGER: accidentally did hard reset\ngit reset --hard HEAD~5\n# Lost 5 commits and uncommitted work\n\n# RECOVERY: find the commit\ngit reflog\n# abc123 HEAD@{0}: reset: moving to HEAD~5\n# def456 HEAD@{1}: commit: feat: add payment\n# ghi789 HEAD@{2}: commit: fix: validation\n\n# Restore to the lost state\ngit reset --hard HEAD@{1}\n# Or: git reset --hard def456\n\n# Alternative: create branch first\ngit checkout -b recovery-branch HEAD@{1}\n# Now inspect and merge back to main","description":"Reflog recovery from accidental hard reset find and restore lost commits."},{"title":"Reset Detached HEAD","useCase":"Fix detached HEAD state.","code":"# You checked out an old commit\ngit checkout v1.0\n# You are in detached HEAD state\n\n# Make changes and commit\necho \"fix\" >> README.md\ngit add .\ngit commit -m \"fix: readme update\"\n\n# Now you want to keep this on a branch\ngit checkout -b hotfix/v1.0-patch\n# OR: create branch without switching\ngit branch hotfix/v1.0-patch\n\n# If you want to discard:\ngit checkout main\n# Detached HEAD changes are lost\n# (can recover from reflog within ~90 days)","description":"Create a branch from detached HEAD to save work done outside any branch."}],"mcqQuestions":[{"question":"What is the default reset mode?","options":["--soft","--mixed","--hard","--keep"],"answer":1,"explanation":"--mixed is the default mode for git reset."},{"question":"What does git reset --soft do?","options":["Discards all changes","Moves HEAD keeps staging and working dir","Resets staging only","Deletes files"],"answer":1,"explanation":"--soft moves HEAD but leaves staging and working directory unchanged."},{"question":"What is the safest reset mode?","options":["--hard","--mixed","--soft","All are equally safe"],"answer":2,"explanation":"--soft is safest as it only moves HEAD without modifying staging or working directory."},{"question":"How do you recover from git reset --hard?","options":["Cannot recover","Use git reflog to find lost commits","Re-download from remote","Recreate from memory"],"answer":1,"explanation":"git reflog shows past HEAD positions for recovery."},{"question":"Why never reset shared branches?","options":["It is slower","It rewrites history breaking other devs","It requires internet","It costs money"],"answer":1,"explanation":"Reset rewrites history. Other developers repos will diverge and require force-sync."},{"question":"What does git reset HEAD -- filename do?","options":["Deletes the file","Unstages the file","Commits the file","Stages the file"],"answer":1,"explanation":"Resets the file in the staging area to match HEAD (unstages it)."},{"question":"Git Reset — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Reset — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Reset — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Reset — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-cherry-pick"] = {"id":"git-cherry-pick","title":"Git Cherry-Pick","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Git cherry-pick applies a specific commit (or commits) from one branch onto the current branch creating a new commit with the same changes.","Useful for: backporting bug fixes to release branches selectively porting features picking specific changes without merging entire branches.","Cherry-pick creates a new SHA even if the changes are identical it is a copy not a move. The original commit remains in its branch.","Conflicts can occur during cherry-pick resolved similarly to merge/rebase conflicts. Multiple cherry-picks can be combined with -n."],"laymanDefinition":"Cherry-pick is like picking individual apples from a neighbor tree without bringing the whole branch. Your neighbor has a tree (branch) with 10 apples (commits). You see one perfect apple (a bug fix) and want it in your basket. You reach over the fence and pick just that one apple the rest stay on the tree.","deepDive":[{"heading":"Cherry-Pick Mechanics","text":"Cherry-pick computes the diff of the target commit and applies it as a new commit on the current branch. It uses the same three-way merge logic as merge. The commit message is copied (can be modified with -x to append source SHA or -n to skip commit). Author information is preserved by default."},{"heading":"Cherry-Pick Use Cases","text":"Backport: apply a bug fix from main to a release/v1.0 branch. Hotfix: apply a fix from a development branch to a production hotfix. Selective feature porting: bring specific features without merging the entire branch. Undo/redo: revert a revert by cherry-picking the original commit."},{"heading":"Cherry-Pick Multiple Commits","text":"git cherry-pick A B C (cherry-pick three commits in order). git cherry-pick A..C (range: commits after A up to and including C). git cherry-pick --stdin < commits.txt (read SHAs from file). Cherry-pick processes commits in order applying each as a separate commit. For conflicts: resolve per commit."},{"heading":"Cherry-Pick with -x","text":"Adding -x appends \"(cherry picked from commit <sha>)\" to the commit message. This creates an audit trail showing where the change originated. Recommended for backports and releases. Without -x the new commit has no reference to the original SHA."},{"heading":"Cherry-Pick Conflicts","text":"If the same code was modified differently in the target branch cherry-pick conflicts. Resolution: edit file git add git cherry-pick --continue. Abort: git cherry-pick --abort. Skip: git cherry-pick --skip. For multiple cherry-picks conflict pauses the sequence resolve and continue for the rest."}],"interviewAnswer":"Cherry-pick is essential for selective commit porting. Use -x for audit trail on backports. Conflicts resolve per commit. For multiple cherry-picks fix conflicts and continue. Cherry-pick does NOT move the original commit it creates a copy. For entire branches prefer merge or rebase.","interviewQuestions":[{"question":"What is git cherry-pick?","answer":"Applies a specific commit from one branch onto the current branch creating a new commit copy."},{"question":"When would you use cherry-pick?","answer":"Backporting bug fixes to release branches selective feature porting hotfix application."},{"question":"Does cherry-pick create a new SHA?","answer":"Yes. Even if changes are identical it creates a new commit object with a new SHA."},{"question":"What does -x do in cherry-pick?","answer":"Appends \"(cherry picked from commit <sha>)\" to the commit message for audit trail."},{"question":"How do you cherry-pick multiple commits?","answer":"git cherry-pick <sha1> <sha2> <sha3> or git cherry-pick <old>..<new>."},{"question":"How do you resolve cherry-pick conflicts?","answer":"Edit conflicting files git add git cherry-pick --continue."},{"question":"How do you abort a cherry-pick?","answer":"git cherry-pick --abort. Returns to pre-cherry-pick state."},{"question":"Can you cherry-pick a merge commit?","answer":"Yes with -m <parent-number> flag to specify which parent to follow."},{"question":"Is the original author preserved in cherry-pick?","answer":"Yes by default. Author name email and date are preserved from the original commit."},{"question":"What is the difference between cherry-pick and rebase?","answer":"Cherry-pick copies specific commits. Rebase replays all commits from one branch onto another."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Git Cherry-Pick</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Branch A</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Commits X Y Z</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Branch B (current)</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Commits A B</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"110\" y1=\"78\" x2=\"140\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pick X</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Copy commit X</text><rect x=\"150\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"200\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pick Z</text><text x=\"200\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Copy commit Z</text><rect x=\"150\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"200\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Result</text><text x=\"200\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">A B X Z</text><rect x=\"260\" y=\"35\" width=\"220\" height=\"150\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"370\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Git Cherry-Pick</text><text x=\"370\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Selectively apply specific commits from one branch to another. New SHAs preserved.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Git Cherry-Pick: Apply specific commits from one branch to another. Selective creates copies. Use -x for audit trail.</text></svg>","codeExamples":[{"title":"Basic Cherry-Pick","useCase":"Pick a single commit.","code":"# Find the commit to cherry-pick\ngit log --oneline feature/login\n# a1b2c3d Add OAuth login\n# b2c3d4e Add validation\n# c3d4e5f Add login form\n\n# Switch to target branch\ngit checkout release/v1.0\n\n# Cherry-pick the OAuth commit only\ngit cherry-pick a1b2c3d\n\n# With -x for audit trail\ngit cherry-pick -x a1b2c3d\n# Message: Add OAuth login\n# (cherry picked from commit a1b2c3d...)\n\n# Cherry-pick without committing\ngit cherry-pick -n a1b2c3d\n# Stages changes you commit manually","description":"Basic cherry-pick to apply a single commit to another branch with optional -x."},{"title":"Cherry-Pick Multiple Commits","useCase":"Apply a range of commits.","code":"# Apply multiple specific commits\ngit cherry-pick a1b2c3d b2c3d4e c3d4e5f\n# Applies in order: a1 b2 c3 to 3 new commits\n\n# Apply a range (after A up to C)\ngit cherry-pick a1b2c3d..c3d4e5f\n# Applies b2 and c3 (exclusive of a1)\n\n# Apply inclusive range\ngit cherry-pick a1b2c3d^..c3d4e5f\n# Applies a1 b2 and c3 (inclusive of a1)\n\n# Combine into one commit with -n\ngit cherry-pick -n a1b2c3d b2c3d4e c3d4e5f\ngit commit -m \"backport: OAuth login fixes\"","description":"Cherry-pick multiple commits by listing SHAs using range syntax or combining with -n."},{"title":"Cherry-Pick a Merge Commit","useCase":"Pick changes from a merge.","code":"# Find the merge commit\ngit log --oneline --merges -3\n# m0n1o2p Merge feature/payment into main\n\n# Cherry-pick following parent 1 (main side)\ngit cherry-pick -m 1 -x m0n1o2p\n\n# Cherry-pick following parent 2 (feature side)\ngit cherry-pick -m 2 -x m0n1o2p\n\n# Without -m cherry-pick rejects merge commits\n# because it does not know which parent to follow","description":"Cherry-pick a merge commit by specifying which parent to follow with -m."},{"title":"Cherry-Pick Sequence with Conflict","useCase":"Handle conflicts in sequence.","code":"# Cherry-pick multiple commits\ngit cherry-pick a1b2c3d b2c3d4e c3d4e5f\n\n# Conflict on b2c3d4e:\n# Fix the conflicted file\ngit add src/file.js\n\n# Continue the cherry-pick sequence\ngit cherry-pick --continue\n# b2c3d4e committed; proceeding to c3d4e5f\n\n# If you want to abort the whole sequence:\ngit cherry-pick --abort\n\n# If you want to skip a problematic commit:\ngit cherry-pick --skip","description":"Cherry-pick pauses on conflicts and resumes with --continue."},{"title":"Cherry-Pick Range from Log","useCase":"Select commits interactively.","code":"# Use git log to find commits by date/author\ngit log --author=\"John\" --oneline -10\n# a1b2c3d feat: add payment gateway\n# b2c3d4e fix: payment timeout\n\n# Cherry-pick specific commits by range\ngit cherry-pick a1b2c3d^..b2c3d4e\n\n# Or use interactive selection with fzf\n# git log --oneline | fzf --multi | awk '{print $1}' | xargs git cherry-pick\n\n# Cherry-pick from another branch without switching\ngit cherry-pick main~2 main~1","description":"Select and cherry-pick commits interactively or by range."}],"mcqQuestions":[{"question":"What is git cherry-pick?","options":["Moves a branch","Applies a specific commit to current branch","Deletes a commit","Merges two branches"],"answer":1,"explanation":"Cherry-pick applies a specific commit from one branch onto the current branch."},{"question":"Does cherry-pick create a new SHA?","options":["No it reuses the same SHA","Yes always creates a new SHA","Depends on -x flag","Only if conflicts occur"],"answer":1,"explanation":"Cherry-pick always creates a new commit object with a new SHA."},{"question":"What does -x do in cherry-pick?","options":["Executes a script","Appends source SHA to message","Extracts changes","Excludes files"],"answer":1,"explanation":"-x appends \"(cherry picked from commit <sha>)\" for audit trail."},{"question":"How do you cherry-pick a merge commit?","options":["Use -m to specify parent","Cannot cherry-pick merges","Use --merge flag","Use -p flag"],"answer":0,"explanation":"Use -m <parent-number> to specify which parent to follow."},{"question":"What happens if a cherry-pick conflicts?","options":["It aborts automatically","It pauses resolve and continue","It skips the commit","It force-applies"],"answer":1,"explanation":"Cherry-pick pauses on conflicts resolve with --continue."},{"question":"Is the original author preserved?","options":["No","Yes by default","Only with -x","Only with -a"],"answer":1,"explanation":"Cherry-pick preserves author name email and date by default."},{"question":"Git Cherry-Pick — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Git Cherry-Pick — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Git Cherry-Pick — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Git Cherry-Pick — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-pull-request"] = {"id":"git-pull-request","title":"Pull Requests","difficulty":"beginner","estimatedMinutes":15,"tldr":["A Pull Request (PR) is a request to merge changes from one branch into another typically from a feature branch into main.","PRs enable code review discussion and automated CI checks before changes are merged. They are the standard collaboration mechanism in Git platforms.","PR lifecycle: create from branch to add reviewers to run CI to address feedback to approve to merge (squash/rebase/merge) to delete branch.","Best practices: small focused PRs (<400 lines) descriptive titles and descriptions link to issues request specific reviewers and update from target branch."],"laymanDefinition":"A Pull Request is like asking a chef to taste your dish before adding it to the menu. You cook your dish (feature) in a separate kitchen (branch). You bring it to the chef and say Please pull my dish into the menu (main). The chef tastes it (code review) checks the recipe (CI) and either approves or asks for changes (feedback).","deepDive":[{"heading":"PR Description Best Practices","text":"Title: conventional commit format (feat: add payment). Description: what why and how. Include screenshots for UI changes. Link related issues: Closes #123. Checklist for tasks. Template: use PR templates (.github/PULL_REQUEST_TEMPLATE.md) for consistency."},{"heading":"Code Review in PRs","text":"Purpose: catch bugs improve code quality share knowledge and ensure consistency. Review types: functionality (does it work) design (is it well-structured) style (naming conventions) testing (are tests adequate). Best practices: review within 24 hours focus on logic not formatting be constructive not critical."},{"heading":"PR Size and Scope","text":"Best PR size: <400 lines changed. Larger PRs are harder to review (cognitive load). Split large features into multiple PRs. Each PR should do ONE thing (single responsibility). Exceptions: refactoring across many files (but explain in description). Use draft PRs for work-in-progress."},{"heading":"CI/CD Integration with PRs","text":"CI runs on every PR: lint tests build security scan. Status checks must pass before merge. Required checks: minimum test coverage no lint errors no security vulnerabilities. Merge gates: require CI pass require X approvals require up-to-date branch."},{"heading":"Merge Methods for PRs","text":"Squash merge: all commits become one commit (clean history). Merge commit: preserves all individual commits and branch structure. Rebase merge: rebases commits onto target then fast-forwards (linear history). Choose based on team convention: squash is most common for GitHub Flow."}],"interviewAnswer":"PRs are the backbone of collaborative development. Write clear descriptions link to issues and keep PRs small (<400 lines). Review code constructively and promptly. Configure CI checks as merge requirements. Choose a merge method that matches your workflow. Delete branches after merge to keep the repo clean.","interviewQuestions":[{"question":"What is a Pull Request?","answer":"A request to merge changes from one branch into another enabling code review and CI checks."},{"question":"What are the benefits of PRs?","answer":"Code review knowledge sharing automated CI checks change tracking and collaboration."},{"question":"What is a good PR size?","answer":"Under 400 lines changed. Smaller PRs are easier to review and less likely to have bugs."},{"question":"What should a PR description include?","answer":"What changed why it changed how it was tested and links to related issues."},{"question":"What is a draft PR?","answer":"A PR marked as work-in-progress. Cannot be merged. Used for early feedback."},{"question":"How do you request a PR review?","answer":"Add reviewers via GitHub/GitLab UI. Use @mentions or auto-assign based on code ownership."},{"question":"What is the recommended CI check for PRs?","answer":"Lint tests build security scan and minimum test coverage percentage."},{"question":"What merge methods are available?","answer":"Squash merge merge commit and rebase merge. Squash is most common for clean history."},{"question":"How do you update a PR branch?","answer":"git merge main or git rebase main in the feature branch then force push."},{"question":"What happens after a PR is merged?","answer":"The feature branch should be deleted. CI/CD deploys if configured for the target branch."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Pull Requests</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Create Branch</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Feature work</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Open PR</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Describe changes</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI Checks</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Lint test build</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Code Review</text><text x=\"215\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Approve changes</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Merge</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Squash/merge/rebase</text><rect x=\"10\" y=\"140\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"65\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Delete Branch</text><text x=\"65\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Clean up</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pull Requests</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code review and CI before merging. Small focused PRs. Clear descriptions.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Pull Requests: Request to merge branches. Code review CI checks collaboration. Keep PRs small and focused.</text></svg>","codeExamples":[{"title":"Creating a PR (GitHub CLI)","useCase":"Create PR from command line.","code":"# Create a feature branch and push\ngit checkout -b feat/add-search\ngit add .\ngit commit -m \"feat: add search functionality\"\ngit push -u origin feat/add-search\n\n# Create PR\ngh pr create --fill --reviewer @team-lead --label enhancement\n# --fill: use commit title+body as PR title+body\n\n# Or with more options:\ngh pr create \\\n  --title \"feat: add search functionality\" \\\n  --body \"Implements full-text search using Elasticsearch\" \\\n  --base main \\\n  --reviewer alice bob \\\n  --assignee @me \\\n  --label enhancement\n\n# View PR in browser\ngh pr view --web","description":"Create PRs from CLI using GitHub CLI with reviewers labels and descriptions."},{"title":"PR Description Template","useCase":"Standardized PR descriptions.","code":"# .github/PULL_REQUEST_TEMPLATE.md\n\n## Description\nBrief description of the changes.\n\n## Type of Change\n- [ ] feat: new feature\n- [ ] fix: bug fix\n- [ ] refactor: code restructuring\n- [ ] test: adding tests\n- [ ] chore: maintenance\n\n## How Has This Been Tested?\n- [ ] Unit tests\n- [ ] Integration tests\n- [ ] Manual testing\n\n## Related Issues\nCloses #123\n\n## Checklist\n- [ ] Code follows style guidelines\n- [ ] Self-review completed\n- [ ] Tests added/passed\n- [ ] Documentation updated","description":"PR template ensures consistent descriptions and helps reviewers understand changes."},{"title":"Automated PR Checks (CI)","useCase":"Required checks before merge.","code":"name: PR Checks\non: pull_request\njobs:\n  lint:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: npm ci && npm run lint\n  test:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: npm ci && npm test\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: npm ci && npm run build\n  security:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: npm audit --audit-level=high","description":"CI pipeline runs lint tests build and security checks on every PR."},{"title":"Auto-Merge PRs","useCase":"Automatically merge when conditions met.","code":"# GitHub: Enable auto-merge on PR\n# gh pr merge --auto --squash\n\n# Or via GitHub UI:\n# PR page > Enable auto-merge > Choose method\n\n# Auto-merge requirements:\n# 1. Required reviews approved\n# 2. All CI status checks pass\n# 3. Branch is up to date with target\n# 4. No merge conflicts\n\n# Once all conditions met GitHub\n# automatically merges the PR\n\n# Useful for:\n# - Dependabot PRs (auto-merge minor upgrades)\n# - Automated releases\n# - Team with fast review turnaround","description":"Auto-merge reduces manual overhead for PRs that meet all requirements."},{"title":"PR Labels and Milestones","useCase":"Organize and prioritize PRs.","code":"# Create labels for PR management\n# gh label create --color 0e8a16 --description \"New feature\" enhancement\n# gh label create --color d73a4a --description \"Bug fix\" bug\n# gh label create --color 0075ca --description \"Documentation\" docs\n\n# Common PR labels:\n# - enhancement: new features\n# - bug: bug fixes\n# - breaking-change: requires attention\n# - needs-review: ready for review\n# - work-in-progress: draft PR\n# - dependencies: Dependabot/automated\n\n# Assign milestone for release tracking\n# gh pr edit 42 --milestone \"v2.0\"\n\n# View PRs by label\n# gh pr list --label enhancement --state open","description":"Labels and milestones organize PRs by type priority and release target."}],"mcqQuestions":[{"question":"What is a Pull Request?","options":["A server-side Git command","A request to merge branches with review","A type of Git branch","A Git configuration file"],"answer":1,"explanation":"A PR requests merging changes from one branch into another with code review and CI."},{"question":"What is a good PR size?","options":["Under 50 lines","Under 400 lines","Over 1000 lines","Any size is fine"],"answer":1,"explanation":"PRs under 400 lines are easier to review and have fewer bugs."},{"question":"What should a PR description include?","options":["Only the title","What why and how plus test info","No description needed","Random text"],"answer":1,"explanation":"PR descriptions should explain what changed why and how it was tested."},{"question":"What is a draft PR?","options":["Unfinished PR for early feedback","A PR ready to merge","A closed PR","A PR with no description"],"answer":0,"explanation":"Draft PRs are work-in-progress and cannot be merged."},{"question":"What merge method keeps the cleanest history?","options":["Merge commit","Squash merge","Rebase merge","All are the same"],"answer":1,"explanation":"Squash merge combines all commits into one creating the cleanest history."},{"question":"What are required checks in PRs?","options":["Optional suggestions","CI checks that must pass before merge","Personal preferences","Browser compatibility tests"],"answer":1,"explanation":"Required CI checks must pass before a PR can be merged."},{"question":"Pull Requests — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Pull Requests — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Pull Requests — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Pull Requests — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-code-review"] = {"id":"git-code-review","title":"Code Review","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Code review is the systematic examination of source code by peers to find bugs improve code quality and share knowledge.","Reviews catch bugs early reduce technical debt enforce coding standards and spread domain knowledge across the team.","Types: formal inspection (structured meetings) lightweight (over-the-shoulder) tool-assisted (PR-based comments) and pair programming (real-time).","Best practices: review in small batches focus on logic not formatting be constructive and specific and prioritize understanding over criticism."],"laymanDefinition":"Code review is like having a second chef taste your soup before serving. You taste it and think it is perfect. Another chef tastes it and says Needs more salt. They are not criticizing you they are making the soup better. Everyone learns what good soup tastes like. Over time the whole team makes better soup.","deepDive":[{"heading":"What to Look for in Code Review","text":"Correctness: does the code work as intended. Design: is it well-structured and maintainable. Security: are there vulnerabilities (injection XSS auth issues). Performance: are there obvious inefficiencies. Testing: are tests adequate and meaningful. Documentation: are complex parts explained."},{"heading":"Review Etiquette","text":"Be respectful: critique the code not the author. Be specific: explain why something is a problem and suggest alternatives. Be timely: review within 24 hours. Focus on what matters: logic > style. Use conventions consistently. Approve when satisfied request changes when needed comment when asking questions."},{"heading":"Review Velocity","text":"Goal: review within 24 hours. Blocking: PRs waiting for review slows the team. Strategies: designate reviewers per area of expertise use auto-assign rotate reviewers enforce review SLAs. Small PRs are reviewed faster than large ones."},{"heading":"Automated vs Human Review","text":"Let tools handle: formatting (Prettier) linting (ESLint) type checking (TypeScript) security scanning (Snyk). Humans focus on: logic correctness design decisions edge cases test quality and domain-specific concerns. Automated checks must pass before human review saves time."},{"heading":"Security-Focused Code Review","text":"Check for: SQL injection (parameterized queries) XSS (output encoding) authentication/authorization flaws (RBAC) CSRF protection insecure data storage (encryption) dependency vulnerabilities (known CVEs) rate limiting and input validation. Security review is critical for auth payment and data handling code."}],"interviewAnswer":"Code review is about team improvement not personal criticism. Focus on correctness design and security. Let automated tools handle formatting. Review promptly within 24 hours. Be specific constructive and respectful. Use checklists to ensure consistency. Review is a skill that improves with practice.","interviewQuestions":[{"question":"What is code review?","answer":"Systematic examination of source code by peers to find bugs improve quality and share knowledge."},{"question":"What are the main goals of code review?","answer":"Catch bugs improve code quality share knowledge enforce standards and reduce technical debt."},{"question":"How quickly should reviews happen?","answer":"Within 24 hours. Fast reviews keep the team moving and prevent blocked PRs."},{"question":"What should automated tools check?","answer":"Formatting linting type checking and security scanning. Humans focus on logic and design."},{"question":"What is the difference between commenting and requesting changes?","answer":"Comment: asking a question or suggesting an option. Request changes: blocking issue that must be addressed."},{"question":"How do you handle disagreement in code review?","answer":"Discuss respectfully. Use data and evidence. Escalate if necessary. Remember the goal is the best outcome for the project."},{"question":"What is a code review checklist?","answer":"A list of common items to verify: correctness security testing edge cases error handling documentation."},{"question":"How do you review security in code?","answer":"Check for injection auth bypass data exposure CSRF and dependency vulnerabilities."},{"question":"What is the optimal PR size for review?","answer":"Under 400 lines. Larger PRs have exponentially more bugs per line."},{"question":"What is over-the-shoulder review?","answer":"One developer looks at another developer screen discussing code in real-time. Informal and fast."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Code Review</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Author</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Submits PR</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Reviewer</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reads code</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Feedback</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Comments changes</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Author Updates</text><text x=\"215\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Address feedback</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Approve</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PR approved</text><rect x=\"10\" y=\"140\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"65\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Merge</text><text x=\"65\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Changes integrated</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Code Review</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Peer review for quality. Focus on logic design and security. Automated tools for formatting.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Code Review: Peer examination of code. Catch bugs improve quality share knowledge. Review within 24 hours.</text></svg>","codeExamples":[{"title":"Code Review Checklist","useCase":"Systematic review process.","code":"# Code Review Checklist\n\n## Functionality\n- Does the code work as described?\n- Are edge cases handled?\n- Is error handling appropriate?\n\n## Design\n- Is the code well-structured?\n- Does it follow SOLID principles?\n- Are there appropriate abstractions?\n\n## Security\n- Is user input validated/sanitized?\n- Are SQL queries parameterized?\n- Is authentication enforced?\n- Are secrets properly handled?\n\n## Testing\n- Are tests meaningful?\n- Do tests cover edge cases?\n- Do tests actually test the change?","description":"Systematic checklist ensures consistent and thorough code reviews."},{"title":"Review Comments Best Practices","useCase":"How to write good review comments.","code":"# Good: Specific and helpful\n# \"This endpoint is missing authentication.\n# Consider adding the @authenticate middleware\n# similar to other endpoints in this controller.\"\n\n# Better with suggestion:\n# \"Suggestion: use Optional chaining to simplify\n#  const user = await getUser(id);\n#  if (!user) return null;\n#  return user.profile.email;\n# becomes:\n#  return (await getUser(id))?.profile?.email;\"\n\n# Avoid: Vague or personal\n# \"This is wrong.\"  (unhelpful)\n# \"You always do this wrong.\" (personal)\n# \"Fix this.\" (no explanation)\n\n# Use conventional comments:\n# \"nitpick: consider renaming for clarity\"\n# \"issue: this will fail if input is null\"\n# \"thought: have you considered using X?\"","description":"Constructive review comments are specific helpful and focus on the code not the author."},{"title":"Auto-Assign Reviewers (CODEOWNERS)","useCase":"Automate reviewer assignment.","code":"# .github/CODEOWNERS\n# Automatically assigns reviewers based on file paths\n\n# Default reviewers for all files\n* @team-lead @senior-dev\n\n# Frontend code reviewers\n/src/components/ @frontend-team\n/src/styles/ @frontend-team\n\n# Backend code reviewers\n/src/api/ @backend-team\n/src/models/ @backend-team\n\n# Critical files: require specific review\n/src/config/security.js @security-officer\n/package.json @tech-lead\n\n# Documentation\n*.md @docs-team\n\n# Infrastructure\n/deploy/ @devops-team\nDockerfile @devops-team","description":"CODEOWNERS auto-assigns reviewers based on changed files ensuring the right people review."},{"title":"Semantic PR Review (AI-Assisted)","useCase":"Enhanced review with automation.","code":"# GitHub Actions: AI code review\nname: AI Code Review\non: pull_request\njobs:\n  review:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - name: AI Review\n        uses: openai/code-review-action@v1\n        with:\n          openai-api-key: ${{ secrets.OPENAI_API_KEY }}\n          github-token: ${{ secrets.GITHUB_TOKEN }}\n\n# Also use static analysis tools:\n# - CodeQL: security analysis\n# - SonarQube: code quality\n# - DeepSource: automated review\n\n# These tools find issues before\n# human review saving reviewer time","description":"AI-assisted and static analysis tools augment human review by catching common issues automatically."},{"title":"Reviewing Tests in PR","useCase":"Evaluate test quality during review.","code":"# Questions to ask when reviewing tests:\n\n# 1. Does the test test the change?\n#    (not unrelated functionality)\n\n# 2. Are edge cases covered?\n#    - Empty inputs\n#    - Null/undefined values\n#    - Maximum values\n#    - Network errors\n\n# 3. Are there integration tests?\n#    Unit test: function works in isolation\n#    Integration: components work together\n\n# 4. Are tests deterministic?\n#    (no random data that fails intermittently)\n\n# 5. Is the test readable?\n#    AAA pattern: Arrange Act Assert\n#    test('should return user when found', () => {\n#      // Arrange\n#      const id = '123';\n#      // Act\n#      const result = getUser(id);\n#      // Assert\n#      expect(result.id).toBe(id);\n#    });","description":"Test review ensures meaningful coverage and reliable CI results."}],"mcqQuestions":[{"question":"What is code review?","options":["Running automated tests","Peer examination of source code","Writing documentation","Deploying to production"],"answer":1,"explanation":"Code review is systematic peer examination of code for bugs quality and knowledge sharing."},{"question":"What should automated tools handle?","options":["Logic correctness","Formatting and linting","Design decisions","Edge case handling"],"answer":1,"explanation":"Automated tools handle formatting linting type checking and security scanning."},{"question":"How fast should reviews happen?","options":["Within a week","Within 24 hours","Within an hour","No deadline"],"answer":1,"explanation":"Reviews should happen within 24 hours to keep the team moving."},{"question":"What is the optimal PR size for review?","options":["Under 100 lines","Under 400 lines","Under 1000 lines","Any size"],"answer":1,"explanation":"PRs under 400 lines are optimal for effective review."},{"question":"What does CODEOWNERS do?","options":["Tracks code ownership","Auto-assigns reviewers","Locks files","Generates documentation"],"answer":1,"explanation":"CODEOWNERS auto-assigns reviewers based on which files are changed in a PR."},{"question":"What should human reviewers focus on?","options":["Code formatting","Logic design and security","Variable naming","Comment style"],"answer":1,"explanation":"Humans focus on logic correctness design decisions security and domain concerns."},{"question":"Code Review — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Code Review — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Code Review — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Code Review — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-ci-cd-pipeline"] = {"id":"git-ci-cd-pipeline","title":"CI/CD Pipeline","difficulty":"intermediate","estimatedMinutes":20,"tldr":["CI/CD (Continuous Integration/Continuous Delivery) automates the building testing and deployment of code changes.","Continuous Integration: automatically build and test every code change. Catch bugs early. Every commit to main must be deployable.","Continuous Delivery: automatically deploy to staging/manual approval to production. Continuous Deployment: automatically deploy to production after tests pass.","Core pipeline stages: Source (code push) to Build (compile/bundle) to Test (unit/integration/e2e) to Security Scan to Deploy (staging/production)."],"laymanDefinition":"CI/CD is like a car manufacturing assembly line. You put raw materials (code) at one end. The conveyor belt runs automatically: first the frame is assembled (build) then quality checks (tests) then safety inspection (security) then it rolls off ready (deploy). Each station must pass before moving to the next. If a station fails the whole line stops.","deepDive":[{"heading":"Continuous Integration (CI)","text":"Every push triggers automated build and tests. CI servers: GitHub Actions GitLab CI Jenkins CircleCI. CI must be: fast (<10 min) reliable (no flaky tests) and comprehensive (lint test build). Benefits: catch bugs immediately reduce merge conflicts enforce quality gates."},{"heading":"Continuous Delivery (CD)","text":"CI + automated deployment to staging. Production deployment requires manual approval. Build artifacts are versioned and stored. Rollback capability: deploy previous version if issues. CD ensures every change is potentially releasable. Common in enterprise environments with compliance requirements."},{"heading":"Continuous Deployment","text":"CI + fully automated deployment to production. Every commit that passes all stages goes live. Requires: high test coverage (>80%) comprehensive monitoring feature flags for gradual rollout and automated rollback. GitOps pattern: Git repository is the single source of truth for deployment state."},{"heading":"Pipeline Stages in Detail","text":"1. Source: checkout code. 2. Install: dependencies (npm ci pip install). 3. Lint: code style (ESLint Prettier). 4. Build: compile bundle (webpack tsc). 5. Test: unit integration e2e. 6. Security: SAST dependency scan container scan. 7. Package: Docker image artifact. 8. Deploy: staging to production."},{"heading":"Pipeline Security","text":"Secrets management: use CI/CD secrets (GitHub Actions secrets vault). Never hardcode secrets in pipeline config. Signed commits: verify PR commits are signed. SBOM: generate software bill of contents. Supply chain: verify dependency integrity (lock files checksums). Least privilege: CI tokens with minimal permissions."}],"interviewAnswer":"CI/CD automates the path from commit to production. Start with CI: build and test every push. Add CD: automate deployment to staging with manual production gate. Evolve to continuous deployment when you have confidence in tests and monitoring. Pipeline security is critical: manage secrets properly and verify supply chain integrity.","interviewQuestions":[{"question":"What is CI/CD?","answer":"Continuous Integration/Continuous Delivery automated build test and deployment pipeline."},{"question":"What is Continuous Integration?","answer":"Automatically building and testing every code change. Ensures every commit is integrated and verified."},{"question":"What is the difference between CD and Continuous Deployment?","answer":"CD: automated deploy to staging manual approval for production. Continuous Deployment: fully automated to production."},{"question":"What are the core pipeline stages?","answer":"Source to Install to Lint to Build to Test to Security to Deploy."},{"question":"What is a build artifact?","answer":"The packaged output of the build stage: Docker image compiled binary or deployment package."},{"question":"How do you handle secrets in CI/CD?","answer":"Use CI/CD secrets management (encrypted variables). Never hardcode secrets in pipeline YAML."},{"question":"What is a flaky test?","answer":"A test that sometimes passes and sometimes fails without code changes. Undermines CI reliability."},{"question":"What is GitOps?","answer":"A pattern where Git is the single source of truth for deployment state. Changes are made via PRs."},{"question":"What is the benefit of fast CI?","answer":"Fast feedback. Developers know immediately if their change broke something. Target: <10 minutes."},{"question":"What is a rollback strategy?","answer":"Ability to revert to a previous deployment version if the current deployment has issues."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CI/CD Pipeline</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Push</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code</text><rect x=\"120\" y=\"35\" width=\"80\" height=\"20\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"160\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"160\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compile</text><rect x=\"210\" y=\"35\" width=\"80\" height=\"20\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Test</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verify</text><rect x=\"300\" y=\"35\" width=\"80\" height=\"20\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"340\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Security</text><text x=\"340\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Scan</text><rect x=\"390\" y=\"35\" width=\"90\" height=\"20\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"435\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"435\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Release</text><line x1=\"110\" y1=\"45\" x2=\"120\" y2=\"45\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"200\" y1=\"45\" x2=\"210\" y2=\"45\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"290\" y1=\"45\" x2=\"300\" y2=\"45\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"380\" y1=\"45\" x2=\"390\" y2=\"45\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"470\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"245\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI/CD Pipeline</text><text x=\"245\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated build test security scan deploy. Every commit verified.</text><rect x=\"10\" y=\"105\" width=\"150\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"85\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI: Build + Test</text><text x=\"85\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast feedback <10 min</text><rect x=\"170\" y=\"105\" width=\"150\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"245\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CD: Staging</text><text x=\"245\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Manual approval gate</text><rect x=\"330\" y=\"105\" width=\"150\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"405\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Continuous Deploy</text><text x=\"405\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fully automated</text><rect x=\"10\" y=\"140\" width=\"470\" height=\"40\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"245\" y=\"160\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pipeline: Source to Build to Test to Security to Deploy. Artifacts versioned. Rollback enabled.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI/CD Pipeline: Automate build test security and deployment. Fast feedback reliable releases.</text></svg>","codeExamples":[{"title":"GitHub Actions CI Pipeline","useCase":"Build and test workflow.","code":"name: CI\non:\n  push:\n    branches: [main develop]\n  pull_request:\n    branches: [main]\n\njobs:\n  build-and-test:\n    runs-on: ubuntu-latest\n    strategy:\n      matrix:\n        node: [16 18 20]\n\n    steps:\n      - uses: actions/checkout@v3\n      - uses: actions/setup-node@v3\n        with:\n          node-version: ${{ matrix.node }}\n          cache: 'npm'\n      - run: npm ci\n      - run: npm run lint\n      - run: npm run build\n      - run: npm test -- --coverage\n      - uses: codecov/codecov-action@v3","description":"GitHub Actions CI pipeline: lint build test across Node.js versions with caching."},{"title":"Multi-Stage Docker Build","useCase":"Optimized build pipeline.","code":"# Dockerfile with multi-stage build\n# Stage 1: Install dependencies\nFROM node:20-alpine AS deps\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci --only=production\n\n# Stage 2: Build\nFROM node:20-alpine AS builder\nWORKDIR /app\nCOPY --from=deps /app/node_modules ./node_modules\nCOPY . .\nRUN npm run build\n\n# Stage 3: Production image\nFROM node:20-alpine AS runner\nWORKDIR /app\nENV NODE_ENV production\nCOPY --from=builder /app/dist ./dist\nCOPY --from=deps /app/node_modules ./node_modules\nEXPOSE 3000\nCMD [\"node\" \"dist/server.js\"]","description":"Multi-stage Docker build produces smaller secure production images."},{"title":"Pipeline with Deployment Gates","useCase":"Staged deployment with approvals.","code":"name: Deploy\non:\n  push:\n    branches: [main]\n\njobs:\n  test:\n    runs-on: ubuntu-latest\n    steps:\n      - run: npm ci && npm test\n\n  deploy-staging:\n    needs: [test]\n    runs-on: ubuntu-latest\n    environment: staging\n    steps:\n      - run: ./deploy.sh staging\n\n  e2e-tests:\n    needs: [deploy-staging]\n    runs-on: ubuntu-latest\n    steps:\n      - run: npm run test:e2e -- --url https://staging.example.com\n\n  deploy-production:\n    needs: [e2e-tests]\n    runs-on: ubuntu-latest\n    environment: production\n    steps:\n      - run: ./deploy.sh production","description":"Staged deployment with environment gates: test to staging to e2e to production."},{"title":"CI/CD Secrets Management","useCase":"Secure pipeline configuration.","code":"# GitHub Actions: set secrets via CLI or UI\n# gh secret set DOCKER_PASSWORD\n# gh secret set AWS_ACCESS_KEY_ID\n# gh secret set SLACK_WEBHOOK_URL\n\n# Use secrets in workflow:\nsteps:\n  - name: Login to Docker Hub\n    uses: docker/login-action@v2\n    with:\n      username: ${{ secrets.DOCKER_USERNAME }}\n      password: ${{ secrets.DOCKER_PASSWORD }}\n\n  - name: Configure AWS\n    run: |\n      aws configure set aws_access_key_id\n        ${{ secrets.AWS_ACCESS_KEY_ID }}\n      aws configure set aws_secret_access_key\n        ${{ secrets.AWS_SECRET_ACCESS_KEY }}\n\n# NEVER hardcode secrets in YAML:\n# BAD: password: mypassword123\n# GOOD: password: ${{ secrets.PASSWORD }}","description":"Secrets management in CI/CD: encrypted variables never hardcoded in pipeline config."},{"title":"Rollback Strategy in Pipeline","useCase":"Automated rollback on failure.","code":"name: Deploy with Rollback\non: push branches: [main]\njobs:\n  deploy:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: |\n          # Save current version for rollback\n          PREV_VERSION=$(cat version.txt)\n          echo \"PREV_VERSION=$PREV_VERSION\" >> $GITHUB_ENV\n\n      - run: ./deploy.sh\n\n      - name: Health Check\n        run: |\n          for i in {1..12}; do\n            STATUS=$(curl -s -o /dev/null -w \"%{http_code}\" https://app.example.com/health)\n            if [ \"$STATUS\" = \"200\" ]; then\n              echo \"Health check passed\"\n              exit 0\n            fi\n            sleep 5\n          done\n          echo \"Health check failed rolling back\"\n          ./rollback.sh $PREV_VERSION\n          exit 1","description":"Health check with automatic rollback on deployment failure."}],"mcqQuestions":[{"question":"What does CI stand for?","options":["Code Integration","Continuous Integration","Computer Interface","Code Inspection"],"answer":1,"explanation":"CI = Continuous Integration: automatically building and testing every code change."},{"question":"What is the difference between CD and Continuous Deployment?","options":["Same thing","CD deploys to staging Continuous Deployment goes to production","CD is manual","Continuous Deployment is slower"],"answer":1,"explanation":"CD typically has a manual production gate; Continuous Deployment is fully automated."},{"question":"What is a build artifact?","options":["Source code","The packaged output of the build stage","A git commit","A test result"],"answer":1,"explanation":"A build artifact is the output: Docker image binary or deployment package."},{"question":"How should secrets be handled in CI/CD?","options":["Hardcoded in YAML","Encrypted CI/CD secrets","In the source code","In documentation"],"answer":1,"explanation":"Secrets must use encrypted CI/CD secret variables never hardcoded."},{"question":"What is a flaky test?","options":["A consistently passing test","A test that intermittently fails","An untested feature","A slow test"],"answer":1,"explanation":"Flaky tests pass/fail unpredictably undermining CI reliability."},{"question":"What is the recommended CI time target?","options":["< 1 minute","< 10 minutes","< 1 hour","< 1 day"],"answer":1,"explanation":"Fast CI (<10 minutes) provides quick feedback to developers."},{"question":"CI/CD Pipeline — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"CI/CD Pipeline — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"CI/CD Pipeline — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"CI/CD Pipeline — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-ci-cd-tools"] = {"id":"git-ci-cd-tools","title":"CI/CD Tools","difficulty":"intermediate","estimatedMinutes":15,"tldr":["CI/CD tools automate the software delivery pipeline from code commit to production deployment.","Popular tools: GitHub Actions (integrated with GitHub) GitLab CI/CD (integrated with GitLab) Jenkins (self-hosted extensible) CircleCI (cloud-based fast).","Selection criteria: integration with your Git platform ease of use scalability pricing and plugin ecosystem.","Modern trends: GitHub Actions dominates for GitHub-hosted projects due to tight integration and large marketplace of actions."],"laymanDefinition":"CI/CD tools are like different brands of coffee machines. GitHub Actions is a Nespresso: integrated easy clean pods (actions). Jenkins is a professional espresso machine: powerful customizable but requires expertise to maintain. CircleCI is a pour-over: fast good results but needs more setup. Choose the one that fits your kitchen (team) and coffee (project).","deepDive":[{"heading":"GitHub Actions","text":"Integrated CI/CD for GitHub repos. YAML-based workflows. Extensive marketplace: 10,000+ actions. Free for public repos. Matrix builds: test across OS/node versions. Self-hosted runners available. Key features: environment protection rules artifact storage and workflow reuse."},{"heading":"GitLab CI/CD","text":"Integrated with GitLab. .gitlab-ci.yml configuration. Auto DevOps: pre-configured pipelines. Built-in container registry and Kubernetes integration. Review Apps: ephemeral environments per MR. Unique: security scanning (SAST DAST) and container scanning built-in."},{"heading":"Jenkins","text":"Self-hosted highly extensible Java-based CI/CD. Massive plugin ecosystem (1000+). Pipeline as Code (Jenkinsfile with Declarative or Scripted syntax). Master/agent architecture. Great for complex enterprise needs. Challenges: maintenance overhead plugin compatibility Java dependency."},{"heading":"CircleCI","text":"Cloud-first CI/CD focused on speed. Orbs: reusable configuration packages. Resource classes: customize CPU/memory per job. SSH debug mode. Parallelism: split tests across containers. Cache: intelligent dependency caching. Pricing based on credits (compute time)."},{"heading":"Tool Selection Guidance","text":"Use GitHub Actions if you are on GitHub. Use GitLab CI/CD if you are on GitLab. Use Jenkins if you need self-hosted or have complex enterprise requirements. Use CircleCI for performance-optimized cloud CI. Avoid: running your own CI server unless you have dedicated DevOps resources."}],"interviewAnswer":"Choose the CI/CD tool that integrates best with your Git platform and team. GitHub Actions is the most popular choice for GitHub projects. Avoid maintaining your own CI server unless necessary. Focus on pipeline reliability and speed over feature count. A simple fast pipeline is better than a complex slow one.","interviewQuestions":[{"question":"What is the most popular CI/CD tool for GitHub?","answer":"GitHub Actions tightly integrated with a large marketplace of pre-built actions."},{"question":"What is Jenkins?","answer":"A self-hosted extensible CI/CD server with a massive plugin ecosystem. Requires maintenance."},{"question":"What are GitHub Actions?","answer":"YAML-based CI/CD workflows integrated into GitHub with a marketplace of reusable actions."},{"question":"What are GitLab CI/CD orbs?","answer":"Reusable configuration packages for CircleCI. Similar to GitHub Actions but for CircleCI."},{"question":"What is Auto DevOps in GitLab?","answer":"Pre-configured CI/CD pipeline that automatically detects your application type and sets up builds tests and deploys."},{"question":"What is a self-hosted runner?","answer":"A CI/CD runner you host on your own infrastructure rather than using the cloud-hosted service."},{"question":"What is matrix build?","answer":"Running the same CI job across multiple OS/version combinations (e.g. Node 16 18 20 on Ubuntu Windows macOS)."},{"question":"What is a CI/CD orb?","answer":"A reusable package of CircleCI configuration that encapsulates jobs commands and executors."},{"question":"What is the advantage of cloud CI over self-hosted?","answer":"No maintenance faster setup automatic scaling and updates. Self-hosted gives more control."},{"question":"What is the main disadvantage of Jenkins?","answer":"Maintenance overhead: need to manage plugins server updates and security patches."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CI/CD Tools</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitHub Actions</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">GitHub integrated</text><rect x=\"120\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"170\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitLab CI/CD</text><text x=\"170\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Built-in</text><rect x=\"230\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"280\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Jenkins</text><text x=\"280\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Self-hosted</text><rect x=\"340\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"390\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CircleCI</text><text x=\"390\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cloud fast</text><rect x=\"10\" y=\"65\" width=\"125\" height=\"20\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"72.5\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitHub Actions</text><text x=\"72.5\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Marketplace YAML</text><rect x=\"145\" y=\"65\" width=\"125\" height=\"20\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"207.5\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitLab CI/CD</text><text x=\"207.5\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto DevOps</text><rect x=\"280\" y=\"65\" width=\"125\" height=\"20\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"342.5\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Jenkins</text><text x=\"342.5\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Plugins customizable</text><rect x=\"415\" y=\"65\" width=\"75\" height=\"20\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"452.5\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CircleCI</text><text x=\"452.5\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Orbs speed</text><rect x=\"10\" y=\"100\" width=\"470\" height=\"70\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"245\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI/CD Tools</text><text x=\"245\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">GitHub Actions GitLab CI Jenkins CircleCI. Choose based on Git platform and team needs.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI/CD Tools: GitHub Actions GitLab CI Jenkins CircleCI. Pick the right tool for your platform and scale.</text></svg>","codeExamples":[{"title":"GitHub Actions Workflow","useCase":"Example CI workflow.","code":"name: Node.js CI\non:\n  push:\n    branches: [main]\n  pull_request:\n    branches: [main]\n\njobs:\n  build:\n    runs-on: ubuntu-latest\n    strategy:\n      matrix:\n        node-version: [18.x 20.x]\n\n    steps:\n      - uses: actions/checkout@v4\n      - name: Use Node.js ${{ matrix.node-version }}\n        uses: actions/setup-node@v3\n        with:\n          node-version: ${{ matrix.node-version }}\n      - run: npm ci\n      - run: npm run build --if-present\n      - run: npm test","description":"Standard GitHub Actions workflow for Node.js CI with matrix build."},{"title":"GitLab CI/CD Pipeline","useCase":"Example .gitlab-ci.yml.","code":"stages:\n  - test\n  - build\n  - deploy\n\ncache:\n  paths:\n    - node_modules/\n\nunit-test:\n  stage: test\n  image: node:20-alpine\n  script:\n    - npm ci\n    - npm test\n  artifacts:\n    reports:\n      junit: junit.xml\n\nbuild:\n  stage: build\n  image: docker:latest\n  services:\n    - docker:dind\n  script:\n    - docker build -t $CI_REGISTRY_IMAGE:$CI_COMMIT_SHA .\n    - docker push $CI_REGISTRY_IMAGE:$CI_COMMIT_SHA","description":"GitLab CI/CD pipeline with test build and stages."},{"title":"Jenkins Pipeline (Jenkinsfile)","useCase":"Declarative Jenkins pipeline.","code":"pipeline {\n    agent any\n    \n    stages {\n        stage('Checkout') {\n            steps {\n                checkout scm\n            }\n        }\n        stage('Install') {\n            steps {\n                sh 'npm ci'\n            }\n        }\n        stage('Test') {\n            steps {\n                sh 'npm test'\n            }\n            post {\n                always {\n                    junit 'junit.xml'\n                }\n            }\n        }\n        stage('Build') {\n            steps {\n                sh 'npm run build'\n            }\n        }\n        stage('Deploy') {\n            steps {\n                sh './deploy.sh'\n            }\n        }\n    }\n    post {\n        failure {\n            mail to: 'team@example.com' subject: 'Pipeline failed'\n        }\n    }\n}","description":"Declarative Jenkins pipeline with stages and post-build actions."},{"title":"CircleCI Config","useCase":"Example .circleci/config.yml.","code":"version: 2.1\norbs:\n  node: circleci/node@5.0\n\njobs:\n  build-and-test:\n    docker:\n      - image: cimg/node:20.0\n    steps:\n      - checkout\n      - node/install-packages:\n          pkg-manager: npm\n      - run:\n          name: Run tests\n          command: npm test\n      - run:\n          name: Build\n          command: npm run build\n\nworkflows:\n  build-and-test:\n    jobs:\n      - build-and-test\n      - deploy:\n          requires:\n            - build-and-test\n          filters:\n            branches:\n              only: main","description":"CircleCI configuration with orbs for reusable config and workflow orchestration."},{"title":"Multi-Cloud CI Matrix","useCase":"Test across environments.","code":"name: Multi-Platform CI\non: [push pull_request]\n\njobs:\n  test:\n    runs-on: ${{ matrix.os }}\n    strategy:\n      matrix:\n        os: [ubuntu-latest windows-latest macos-latest]\n        node: [16 18 20]\n        exclude:\n          - os: windows-latest\n            node: 16\n\n    steps:\n      - uses: actions/checkout@v3\n      - uses: actions/setup-node@v3\n        with:\n          node-version: ${{ matrix.node }}\n      - run: npm ci\n      - run: npm test\n\n# Matrix runs 3 OS x 3 Node = 9 jobs\n# Exclude reduces to 8 (no node 16 on Windows)","description":"Matrix CI testing across operating systems and Node.js versions."}],"mcqQuestions":[{"question":"Which CI/CD tool is most popular for GitHub?","options":["Jenkins","GitHub Actions","CircleCI","GitLab CI"],"answer":1,"explanation":"GitHub Actions is the most popular choice for GitHub-hosted repositories."},{"question":"What is Jenkins?","options":["Cloud CI service","Self-hosted CI/CD server","Git hosting","Package manager"],"answer":1,"explanation":"Jenkins is a self-hosted extensible CI/CD server with a large plugin ecosystem."},{"question":"What are GitHub Actions?","options":["Git commands","YAML CI/CD workflows","Browser extensions","Code formatters"],"answer":1,"explanation":"GitHub Actions are YAML-based CI/CD workflows with a marketplace of reusable actions."},{"question":"What is the main advantage of cloud CI?","options":["More control","No maintenance automatic scaling","Cheaper","More secure"],"answer":1,"explanation":"Cloud CI requires no infrastructure maintenance and scales automatically."},{"question":"What does matrix build test?","options":["Database schemas","Multiple OS/version combinations","UI layouts","Network latency"],"answer":1,"explanation":"Matrix builds test across combinations of operating systems and runtime versions."},{"question":"What is Jenkins Pipeline as Code?","options":["Jenkinsfile in repo","Visual pipeline editor","CLI configuration","XML config files"],"answer":0,"explanation":"Jenkins Pipeline as Code uses a Jenkinsfile stored in the repository."},{"question":"CI/CD Tools — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"CI/CD Tools — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"CI/CD Tools — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"CI/CD Tools — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-build-automation"] = {"id":"git-build-automation","title":"Build Automation","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Build automation is the process of automating the compilation packaging and preparation of source code into deployable artifacts.","Key tools: npm/yarn (JS) Maven/Gradle (Java) pip (Python) make (C/C++) Webpack/Vite (frontend bundling) Docker (containerization).","Build outputs: compiled binaries bundled JavaScript Docker images deployment packages and versioned artifacts.","Best practices: deterministic builds (same input = same output) fast incremental builds artifact versioning and reproducible builds."],"laymanDefinition":"Build automation is like a recipe that turns ingredients into a cake automatically. You put flour eggs sugar (source code) into a machine. It mixes (compiles) bakes (bundles) and packages the cake (artifact) ready for delivery. The same recipe always produces the same cake. No manual steps no forgetting ingredients.","deepDive":[{"heading":"Build Determinism and Reproducibility","text":"Deterministic build: same source always produces identical output. Key for trust and debugging. Achieved by: lock files (package-lock.json) fixed tool versions (Docker) no network-dependent steps timestamp control (SOURCE_DATE_EPOCH). Reproducible builds verify integrity across different build environments."},{"heading":"Build Tools by Ecosystem","text":"JavaScript/TypeScript: npm scripts Webpack Vite esbuild tsc Babel. Java: Maven (XML) Gradle (Groovy/Kotlin). Python: pip setuptools Poetry. Go: go build. Rust: cargo build. C/C++: make CMake. Multi-language: Bazel Nix. Docker: multi-stage builds for optimized images."},{"heading":"Incremental and Cache-Based Builds","text":"Incremental: only rebuild changed files (fast). Tools: webpack --watch Vite (HMR) tsc --incremental. Caching: store build outputs between CI runs (npm cache Docker layer caching). Cache keys: lock file hash source file hash tool version. Trade-off: cache invalidation complexity vs build speed."},{"heading":"Build Artifact Management","text":"Versioning: semantic version + commit SHA (myapp-1.2.3-a1b2c3d). Storage: artifact registry (Docker Hub GHCR npm registry S3). Retention: keep N latest versions tag important versions. Cleanup: automated deletion of old artifacts. SBOM: generate software bill of materials with each build."},{"heading":"Build Security","text":"Supply chain: verify dependency integrity (lock files checksums). No secrets in build: build args should not expose secrets. Minimal base images: Alpine distroless. SBOM generation: CycloneDX SPDX. Image scanning: Trivy Grype Snyk. Signing: cosign for container images. Provenance: SLSA attestations."}],"interviewAnswer":"Build automation is the foundation of CI/CD. Ensure builds are deterministic and fast. Use caching for speed. Version artifacts consistently (semver + commit SHA). Secure the build pipeline: verify dependencies scan images and sign artifacts. A reliable build pipeline enables confident deployments.","interviewQuestions":[{"question":"What is build automation?","answer":"Automating the compilation packaging and preparation of source code into deployable artifacts."},{"question":"What is a deterministic build?","answer":"A build that produces identical output from the same source code regardless of when or where it is built."},{"question":"What are common build tools for JavaScript?","answer":"npm scripts Webpack Vite esbuild tsc. For bundling: Webpack Vite. For compilation: Babel tsc esbuild."},{"question":"What is incremental build?","answer":"Only rebuilding files that changed since the last build. Much faster than full rebuilds."},{"question":"What is a build artifact?","answer":"The output of a build: compiled binary bundled JS Docker image or deployment package."},{"question":"How do you version build artifacts?","answer":"Use semantic versioning combined with commit SHA: myapp-1.2.3-a1b2c3d."},{"question":"What is Docker layer caching?","answer":"Docker caches each layer of a Dockerfile. Only layers that change are rebuilt. Speeds up builds significantly."},{"question":"What is an SBOM?","answer":"Software Bill of Materials a list of all components and dependencies in a build. Used for vulnerability tracking."},{"question":"What is supply chain security?","answer":"Ensuring the integrity of dependencies and build tools. Lock files checksums signed commits."},{"question":"What is a multi-stage Docker build?","answer":"A Dockerfile with multiple FROM statements. Early stages have build tools later stages are minimal production images."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Build Automation</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Source</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code</text><rect x=\"120\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"170\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Install</text><text x=\"170\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dependencies</text><rect x=\"230\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"280\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Compile</text><text x=\"280\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Transpile bundle</text><rect x=\"340\" y=\"35\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"390\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Package</text><text x=\"390\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Docker image</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Version</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Semver + SHA</text><rect x=\"120\" y=\"65\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"170\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache</text><text x=\"170\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Incremental build</text><rect x=\"230\" y=\"65\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"280\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Security</text><text x=\"280\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Scan + sign</text><rect x=\"340\" y=\"65\" width=\"100\" height=\"20\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"390\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Publish</text><text x=\"390\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Registry</text><rect x=\"10\" y=\"95\" width=\"430\" height=\"80\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"225\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build Automation</text><text x=\"225\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deterministic build to artifact versioning to caching to security scanning. Reliable reproducible secure.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Build Automation: Automate compile bundle package. Deterministic incremental cached. Secure supply chain.</text></svg>","codeExamples":[{"title":"Node.js Build Script (package.json)","useCase":"Standard build scripts.","code":"{\n  \"scripts\": {\n    \"build\": \"npm run build:ts && npm run build:vite\",\n    \"build:ts\": \"tsc --incremental\",\n    \"build:vite\": \"vite build\",\n    \"build:prod\": \"NODE_ENV=production npm run build\",\n    \"clean\": \"rm -rf dist .tsbuildinfo\",\n    \"prebuild\": \"npm run clean && npm ci\",\n    \"postbuild\": \"npm run test && npm run sbom\"\n  }\n}","description":"Standard Node.js build scripts with incremental TS compilation and production optimizations."},{"title":"Docker Multi-Stage Build","useCase":"Optimized Dockerfile.","code":"# Stage 1: Build\nFROM node:20-alpine AS builder\nWORKDIR /build\nCOPY package*.json .\nRUN npm ci\nCOPY . .\nRUN npm run build\n\n# Stage 2: Production\nFROM node:20-alpine\nWORKDIR /app\nCOPY --from=builder /build/dist ./dist\nCOPY --from=builder /build/node_modules ./node_modules\nCOPY package.json .\nUSER node\nEXPOSE 3000\nCMD [\"node\" \"dist/server.js\"]","description":"Multi-stage Docker build separates build tools from production runtime for smaller images."},{"title":"Build Caching in CI","useCase":"Cache strategies for faster builds.","code":"name: Fast Build\non: push\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n\n      # Cache npm dependencies\n      - uses: actions/cache@v3\n        with:\n          path: ~/.npm\n          key: npm-${{ hashFiles('package-lock.json') }}\n          restore-keys: npm-\n\n      # Cache TypeScript incremental build\n      - uses: actions/cache@v3\n        with:\n          path: .tsbuildinfo\n          key: tsbuild-${{ hashFiles('src/**/*.ts') }}\n\n      # Cache Docker layers\n      - uses: docker/setup-buildx-action@v2\n      - uses: docker/build-push-action@v4\n        with:\n          cache-from: type=gha\n          cache-to: type=gha,mode=max\n\n      - run: npm ci && npm run build","description":"Multi-level caching: npm packages TS build info and Docker layers for fastest CI builds."},{"title":"Artifact Versioning Strategy","useCase":"Version your build outputs.","code":"# Generate version from git tag + commit\nVERSION=$(git describe --tags --always --dirty)\nCOMMIT=$(git rev-parse --short HEAD)\nBUILD_TIME=$(date -u +'%Y-%m-%dT%H:%M:%SZ')\n\n# In Node.js: inject version at build time\necho \"{\n  \\\"version\\\": \\\"$VERSION\\\",\n  \\\"commit\\\": \\\"$COMMIT\\\",\n  \\\"buildTime\\\": \\\"$BUILD_TIME\\\"\n}\" > public/build-info.json\n\n# Tag Docker image with version\ndocker build -t myapp:$VERSION .\ndocker tag myapp:$VERSION myapp:latest\ndocker push myapp:$VERSION\ndocker push myapp:latest\n\n# Also tag with major version\nMAJOR=$(echo $VERSION | cut -d. -f1)\ndocker tag myapp:$VERSION myapp:$MAJOR.x\ndocker push myapp:$MAJOR.x","description":"Version artifacts with git tag commit SHA and timestamp for traceability."},{"title":"SBOM Generation (CycloneDX)","useCase":"Generate software bill of materials.","code":"# Install CycloneDX tool\n# npm install -g @cyclonedx/bom\n\n# Generate SBOM\ncyclonedx-bom -o sbom.xml\n\n# Or as part of CI:\nname: SBOM\non: push\njobs:\n  sbom:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v3\n      - run: npm ci\n      - name: Generate SBOM\n        uses: CycloneDX/gh-node-module-generatebom@v1\n        with:\n          path: .\n          output: ./sbom.xml\n      - name: Upload SBOM\n        uses: actions/upload-artifact@v3\n        with:\n          name: sbom\n          path: ./sbom.xml","description":"SBOM generation creates a machine-readable inventory of all dependencies for vulnerability tracking."}],"mcqQuestions":[{"question":"What is build automation?","options":["Manual compilation","Automated compile package and prepare artifacts","Code formatting","Database migration"],"answer":1,"explanation":"Build automation compiles packages and prepares source code into deployable artifacts."},{"question":"What is a deterministic build?","options":["Random output","Identical output from same source","Faster build","Smaller output"],"answer":1,"explanation":"Deterministic builds produce identical output from the same source every time."},{"question":"What does incremental build mean?","options":["Build everything","Only rebuild changed files","Build on server","Build with warnings"],"answer":1,"explanation":"Incremental builds only recompile files that changed since the last build."},{"question":"What is the benefit of multi-stage Docker builds?","options":["More layers","Smaller production images","Faster networking","More memory"],"answer":1,"explanation":"Multi-stage builds separate build tools from runtime producing smaller secure images."},{"question":"How should artifacts be versioned?","options":["Just date","Semver + commit SHA","Random string","No versioning needed"],"answer":1,"explanation":"Artifacts should use semantic version combined with commit SHA for traceability."},{"question":"What is an SBOM?","options":["Build script","Software Bill of Materials","Build optimizer","Source code backup"],"answer":1,"explanation":"An SBOM is a machine-readable inventory of all components and dependencies."},{"question":"Build Automation — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Build Automation — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Build Automation — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Build Automation — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-test-automation"] = {"id":"git-test-automation","title":"Test Automation","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Test automation is the practice of using software tools to execute pre-scripted tests on a codebase automatically rather than manually.","Automated tests run on every push in CI/CD pipelines catching regressions early. Key types: unit tests (isolated functions) integration tests (component interaction) end-to-end tests (full user workflows).","Key frameworks: Jest Mocha (JS) JUnit (Java) PyTest (Python) Selenium Cypress Playwright (browser). Tests should be fast deterministic and isolated from external services.","Best practices: test pyramid (many unit few e2e) arrange-act-act pattern avoid test interdependence mock external services and aim for >80% coverage on critical paths."],"laymanDefinition":"Test automation is like a robot quality inspector on an assembly line. Instead of a human checking every tenth widget the robot checks EVERY widget instantly. It never gets tired never misses a defect and works 24/7. The initial setup takes effort but once running it catches problems that would otherwise reach the customer.","deepDive":[{"heading":"Test Pyramid","text":"Unit tests (70%): test individual functions/classes. Fast (ms) run on every save. Integration tests (20%): test component interaction database file system. Slower but catch API contract issues. End-to-end tests (10%): test full user flows in browser. Slow (seconds) but catch real user-facing bugs."},{"heading":"Unit Testing Best Practices","text":"Test one thing per test. Use descriptive names: test(\"should return user when valid id\"). Arrange-Act-Assert pattern. Mock external dependencies (HTTP DB). Test edge cases: empty input null undefined boundaries. Avoid testing implementation details test behavior. Use code coverage to find untested paths."},{"heading":"Integration Testing","text":"Test real interactions between components: API endpoints database queries file I/O. Use test containers for databases. Run against a test environment not production. Integration tests catch: schema mismatches incorrect API contracts broken serialization. Slower than unit tests but higher confidence."},{"heading":"End-to-End Testing","text":"Browser tests that simulate real user interactions. Tools: Cypress Playwright Selenium. Test critical user journeys: login signup checkout search. Run against staging environment. Flaky tests are the biggest challenge. Use retry mechanisms and independent test data."},{"heading":"CI/CD Test Integration","text":"Unit tests: run on every push (fast). Integration tests: run on PR to main (medium). E2E tests: run on merge to main (slow). Parallel test execution across multiple CI runners. Test splitting: distribute tests by file/execution time. Fail fast: cancel CI if a critical test fails."}],"interviewAnswer":"Test automation is non-negotiable for CI/CD. Start with unit tests they give the best speed-value ratio. Add integration tests for critical paths. Add a few E2E tests for key user journeys. Keep tests fast and reliable. A flaky test is worse than no test because it erodes trust in the pipeline.","interviewQuestions":[{"question":"What is test automation?","answer":"Using software tools to execute pre-scripted tests automatically on each code change."},{"question":"What are the three main test types?","answer":"Unit (isolated functions) Integration (component interaction) E2E (full user workflows)."},{"question":"What is the test pyramid?","answer":"Many unit tests (70%) some integration tests (20%) few E2E tests (10%)."},{"question":"What is the Arrange-Act-Assert pattern?","answer":"AAA: set up test data (Arrange) execute the code (Act) verify the result (Assert)."},{"question":"Why mock external dependencies in tests?","answer":"To make tests fast deterministic and isolated from network/database failures."},{"question":"What is a flaky test?","answer":"A test that sometimes passes and sometimes fails without code changes. Undermines CI reliability."},{"question":"What is code coverage?","answer":"A metric measuring what percentage of code is executed during tests. Not a quality guarantee."},{"question":"What is parallel test execution?","answer":"Running multiple test files simultaneously across CI runners to reduce total test time."},{"question":"What is the difference between Cypress and Playwright?","answer":"Both are E2E frameworks. Cypress is JS-only with better debugging. Playwright supports multiple languages and browsers."},{"question":"What is a test fixture?","answer":"A fixed state of data used as a baseline for running tests ensuring test reproducibility."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Test Automation</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Unit (70%)</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast ms</text><line x1=\"110\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"140\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"190\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Integration (20%)</text><text x=\"190\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Medium s</text><line x1=\"240\" y1=\"48\" x2=\"260\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">E2E (10%)</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Slow seconds</text><rect x=\"140\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"190\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI Pipeline</text><text x=\"190\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated per push</text><rect x=\"140\" y=\"100\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"190\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Parallel</text><text x=\"190\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Multiple runners</text><rect x=\"10\" y=\"100\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"60\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Coverage</text><text x=\"60\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">>80% critical paths</text><rect x=\"260\" y=\"35\" width=\"220\" height=\"150\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"370\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Test Automation</text><text x=\"370\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated testing in CI/CD: unit integration E2E. Fast reliable deterministic. Pyramid principle.</text><text x=\"100\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Test Automation: Automated tests in CI/CD. Unit Integration E2E pyramid. Fast deterministic isolated.</text></svg>","codeExamples":[{"title":"Unit Test Example (Jest)","useCase":"Test a function in isolation.","code":"// math.js\nfunction divide(a, b) {\n  if (b === 0) throw new Error('Cannot divide by zero');\n  return a / b;\n}\n\n// math.test.js\ndescribe('divide', () => {\n  test('divides positive numbers', () => {\n    expect(divide(10, 2)).toBe(5);\n  });\n\n  test('throws on zero divisor', () => {\n    expect(() => divide(10, 0)).toThrow('Cannot divide by zero');\n  });\n\n  test('handles negative numbers', () => {\n    expect(divide(-10, 2)).toBe(-5);\n  });\n\n  test('handles decimal results', () => {\n    expect(divide(7, 3)).toBeCloseTo(2.333, 3);\n  });\n});","description":"Unit test example with Jest covering normal edge case and error paths."},{"title":"Integration Test (Supertest)","useCase":"Test an API endpoint.","code":"const request = require('supertest');\nconst app = require('./app');\n\ndescribe('POST /api/users', () => {\n  test('creates a new user', async () => {\n    const res = await request(app)\n      .post('/api/users')\n      .send({ name: 'Alice', email: 'alice@test.com' });\n\n    expect(res.status).toBe(201);\n    expect(res.body).toHaveProperty('id');\n    expect(res.body.name).toBe('Alice');\n  });\n\n  test('rejects duplicate email', async () => {\n    const res = await request(app)\n      .post('/api/users')\n      .send({ name: 'Bob', email: 'alice@test.com' });\n\n    expect(res.status).toBe(409);\n    expect(res.body.error).toContain('exists');\n  });\n\n  test('validates required fields', async () => {\n    const res = await request(app)\n      .post('/api/users')\n      .send({});\n\n    expect(res.status).toBe(400);\n  });\n});","description":"Integration test for a REST API endpoint covering success error and validation cases."},{"title":"CI Test Configuration (GitHub Actions)","useCase":"Run tests in CI pipeline.","code":"name: Test Suite\non: [push, pull_request]\n\njobs:\n  test:\n    runs-on: ubuntu-latest\n    strategy:\n      matrix:\n        node: [18, 20]\n\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with:\n          node-version: ${{ matrix.node }}\n      - run: npm ci\n      - run: npm run lint\n      - run: npm test -- --coverage\n      - uses: codecov/codecov-action@v3\n      - run: npm run test:integration\n        if: github.ref == 'refs/heads/main'","description":"CI pipeline running lint unit tests with coverage and integration tests on main."},{"title":"Mocking External Dependencies","useCase":"Isolate tests from external services.","code":"// user-service.test.js\njest.mock('./email-service');\nconst { sendWelcomeEmail } = require('./email-service');\nconst { createUser } = require('./user-service');\n\ntest('sends welcome email on user creation', async () => {\n  sendWelcomeEmail.mockResolvedValue(true);\n\n  const user = await createUser({ name: 'Alice', email: 'a@b.com' });\n\n  expect(sendWelcomeEmail).toHaveBeenCalledWith(user.email);\n  expect(sendWelcomeEmail).toHaveBeenCalledTimes(1);\n});\n\ntest('handles email failure gracefully', async () => {\n  sendWelcomeEmail.mockRejectedValue(new Error('SMTP down'));\n\n  const user = await createUser({ name: 'Bob', email: 'b@c.com' });\n\n  expect(user).toBeDefined();\n  expect(console.error).toHaveBeenCalled();\n});","description":"Mock external services to make tests deterministic and fast."},{"title":"Parallel Test Execution (Jest)","useCase":"Run tests faster in parallel.","code":"// jest.config.js\nmodule.exports = {\n  maxWorkers: '50%',  // Use 50% of CPU cores\n  testMatch: ['**/*.test.js'],\n  testTimeout: 10000,\n  bail: 1,  // Stop after first failure in CI\n  verbose: true,\n\n  // Shard tests across CI runners\n  // --shard=1/4 on first of 4 runners\n};\n\n# Run in CI with sharding:\n# npx jest --shard=${{ matrix.shard }}/4\n#\n# Split by file:\n# npx jest --listTests | split -l 10\n#\n# Use jest --onlyChanged for local dev\n# jest --changedSince=main","description":"Parallel test execution with Jest sharding distributes tests across CI runners for speed."}],"mcqQuestions":[{"question":"What is the test pyramid?","options":["All tests are equal","Many unit some integration few E2E","Only E2E tests","Only unit tests"],"answer":1,"explanation":"Test pyramid: many unit tests (fast) some integration medium E2E (few slow)."},{"question":"What is the Arrange-Act-Assert pattern?","options":["Setup execute verify","Act arrange assert","Assert act arrange","Random order"],"answer":0,"explanation":"AAA: Arrange (setup) Act (execute) Assert (verify)."},{"question":"Why mock external services?","options":["Make tests faster","Tests become deterministic and fast","Less code to write","Better coverage"],"answer":1,"explanation":"Mocking makes tests deterministic by removing external dependencies and network calls."},{"question":"What is a flaky test?","options":["A consistently passing test","A test that intermittently fails","A very slow test","A new test"],"answer":1,"explanation":"Flaky tests pass/fail unpredictably undermining CI reliability and developer trust."},{"question":"What is code coverage?","options":["Percentage of code executed by tests","Number of test files","Test execution time","Number of assertions"],"answer":0,"explanation":"Code coverage measures how much of the codebase is executed during tests."},{"question":"What is the benefit of parallel test execution?","options":["Fewer tests needed","Reduced total CI test time","Better coverage","Simpler tests"],"answer":1,"explanation":"Parallel execution dramatically reduces total CI pipeline time by running tests across multiple runners."},{"question":"Test Automation — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Test Automation — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Test Automation — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Test Automation — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-deployment-automation"] = {"id":"git-deployment-automation","title":"Deployment Automation","difficulty":"advanced","estimatedMinutes":20,"tldr":["Deployment automation is the practice of automatically releasing software changes to production environments without manual intervention.","Key components: CI/CD pipeline build artifacts artifact registry deployment strategies (blue-green canary rolling) and health checks with auto-rollback.","Tools: GitHub Actions GitLab CI Jenkins ArgoCD (GitOps) Terraform (infrastructure) Docker Kubernetes. Modern deployments target containers/orchestrators.","Best practices: immutable infrastructure (never modify a running server replace it) infrastructure as code zero-downtime deployments and feature flags for gradual rollouts."],"laymanDefinition":"Deployment automation is like an autopilot system for an airplane. You set the destination (production) and the autopilot handles takeoff (build) navigation (pipeline gates) landing (deploy) and even go-arounds (rollback) if conditions are unsafe. The pilot monitors but does not manually fly. Manual deployment is like flying by hand every time exhausting and error-prone.","deepDive":[{"heading":"Deployment Strategies","text":"Blue-Green: two identical environments switch traffic. Zero downtime. Canary: gradual traffic shift 1% 5% 10% 100%. Risk mitigation. Rolling: replace instances one by one. Good for clusters. Recreate: stop old start new. Simple but downtime. Choose based on risk tolerance and infrastructure."},{"heading":"Immutable Infrastructure","text":"Never patch a running server. Instead build a new image and replace. Benefits: consistent environments no configuration drift easy rollback (deploy previous image). Implemented via: Docker images AMIs VM snapshots. Coupled with IaC (Terraform Pulumi CloudFormation) for full reproducibility."},{"heading":"Infrastructure as Code (IaC)","text":"Define infrastructure in version-controlled config files. Tools: Terraform (multi-cloud) Pulumi (programmable) AWS CDK (TypeScript) Ansible (config management). Benefits: reviewable auditable repeatable. IaC + immutable infrastructure = full environment reproducibility."},{"heading":"Rollback Strategies","text":"Automatic rollback on health check failure. Strategies: revert to previous deployment (blue-green) scale up previous canary group (canary) re-run previous CI build (rolling). Database rollbacks: backward-compatible migrations or feature flags. Always test rollback procedure."},{"heading":"GitOps Pattern","text":"Git is the single source of truth for deployment state. Tools: ArgoCD Flux (Kubernetes). Agent in cluster syncs to desired state in Git. Changes via PR to Git repo. Benefits: audit trail review process automatic drift correction. Declarative: desired state vs actual state."}],"interviewAnswer":"Deployment automation is the final frontier of CI/CD maturity. Start with simple scripts then adopt blue-green or canary deployments. Use immutable infrastructure and IaC for reproducibility. Implement health checks and auto-rollback. GitOps provides the highest level of auditability and control for Kubernetes environments.","interviewQuestions":[{"question":"What is deployment automation?","answer":"Automatically releasing software changes to production without manual intervention."},{"question":"What is blue-green deployment?","answer":"Two identical environments. Switch traffic from blue (old) to green (new). Instant rollback."},{"question":"What is canary deployment?","answer":"Gradually shift traffic to new version: 1% 5% 10% 100%. Monitor each step."},{"question":"What is immutable infrastructure?","answer":"Never modify running servers. Build new images and replace. Configuration drift eliminated."},{"question":"What is Infrastructure as Code?","answer":"Defining infrastructure (servers networks) in version-controlled config files."},{"question":"What is GitOps?","answer":"Git as single source of truth for deployment state. Agent syncs cluster to desired state in Git."},{"question":"What is automatic rollback?","answer":"Deploy health checks abort deployment and revert if checks fail."},{"question":"What is zero-downtime deployment?","answer":"Deploying without interrupting service. Achieved via blue-green rolling or canary strategies."},{"question":"What is a deployment artifact?","answer":"The versioned deployable unit: Docker image compiled binary or deployment package."},{"question":"What is a health check endpoint?","answer":"A URL (e.g. /health) that returns the application status. Used by load balancers and deploy pipelines."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Deployment Automation</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compile + test</text><line x1=\"110\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"140\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"190\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Package</text><text x=\"190\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Docker image</text><line x1=\"240\" y1=\"48\" x2=\"260\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blue-Green</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Switch traffic</text><rect x=\"140\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"190\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Canary</text><text x=\"190\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Gradual rollout</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Health Check</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verify deployment</text><rect x=\"140\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"190\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rollback</text><text x=\"190\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-revert</text><rect x=\"260\" y=\"35\" width=\"220\" height=\"150\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"370\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deployment Automation</text><text x=\"370\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Automated release pipeline: build to package to deploy. Blue-green canary rolling. Health checks rollback.</text><text x=\"100\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Deployment Automation: Blue-green canary rolling deployments. Health checks auto-rollback immutable infrastructure.</text></svg>","codeExamples":[{"title":"Blue-Green Deployment Script","useCase":"Switch traffic between environments.","code":"#!/bin/bash\n# Blue-Green deployment\n\n# Variables\nBLUE_URL=\"https://blue.app.com/health\"\nGREEN_URL=\"https://green.app.com/health\"\nACTIVE_COLOR=$(cat /deploy/active-color.txt)\n\n# Deploy to inactive environment\nif [ \"$ACTIVE_COLOR\" = \"blue\" ]; then\n  NEW_COLOR=\"green\"\nelse\n  NEW_COLOR=\"blue\"\nfi\n\necho \"Deploying to $NEW_COLOR...\"\n./deploy-to.sh $NEW_COLOR\n\n# Health check the new environment\nsleep 10\nSTATUS=$(curl -s -o /dev/null -w \"%{http_code}\"\n  \"${NEW_COLOR^^}_URL\")\n\nif [ \"$STATUS\" != \"200\" ]; then\n  echo \"Health check failed rolling back\"\n  exit 1\nfi\n\n# Switch traffic\necho \"Switching traffic to $NEW_COLOR\"\necho \"$NEW_COLOR\" > /deploy/active-color.txt\n./update-load-balancer.sh $NEW_COLOR\n\necho \"Deployment to $NEW_COLOR complete\"","description":"Blue-green deployment script deploys to inactive environment health checks then switches traffic."},{"title":"Canary Deployment with Kubernetes","useCase":"Gradual rollout in K8s.","code":"# Kubernetes canary deployment\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: myapp-canary\nspec:\n  replicas: 1  # 10% of main 10 replicas\n  selector:\n    matchLabels:\n      app: myapp\n      track: canary\n  template:\n    metadata:\n      labels:\n        app: myapp\n        track: canary\n    spec:\n      containers:\n      - name: myapp\n        image: myapp:1.2.3-canary\n        readinessProbe:\n          httpGet:\n            path: /health\n            port: 8080\n\n# Service splits traffic via label selector\n# Canary gets 1 replica = ~10% traffic\n# Monitor errors for 10 minutes\n# If OK scale canary to 10 then scale down main","description":"Kubernetes canary deployment using replicas for traffic splitting between versions."},{"title":"Terraform IaC Example","useCase":"Define infrastructure as code.","code":"# main.tf - AWS infrastructure\nprovider \"aws\" {\n  region = \"us-east-1\"\n}\n\nresource \"aws_ecs_cluster\" \"main\" {\n  name = \"myapp-cluster\"\n}\n\nresource \"aws_ecs_service\" \"app\" {\n  name            = \"myapp\"\n  cluster         = aws_ecs_cluster.main.id\n  task_definition = aws_ecs_task_definition.app.arn\n  desired_count   = 3\n  launch_type     = \"FARGATE\"\n\n  network_configuration {\n    subnets         = aws_subnet.private[*].id\n    security_groups = [aws_security_group.app.id]\n  }\n\n  deployment_controller {\n    type = \"CODE_DEPLOY\"  # Blue-green\n  }\n}","description":"Terraform defines AWS ECS infrastructure as code for repeatable deployments."},{"title":"ArgoCD GitOps Application","useCase":"GitOps deployment with ArgoCD.","code":"# argocd-application.yaml\napiVersion: argoproj.io/v1alpha1\nkind: Application\nmetadata:\n  name: myapp\n  namespace: argocd\nspec:\n  project: default\n  source:\n    repoURL: https://github.com/company/myapp-config.git\n    targetRevision: HEAD\n    path: k8s/production\n  destination:\n    server: https://kubernetes.default.svc\n    namespace: production\n  syncPolicy:\n    automated:\n      prune: true  # Remove resources not in Git\n      selfHeal: true  # Revert manual changes\n    syncOptions:\n      - CreateNamespace=true\n\n# GitOps flow:\n# 1. Update k8s/production/deployment.yaml in Git\n# 2. PR review and merge to main\n# 3. ArgoCD detects drift and syncs cluster\n# 4. Cluster matches desired state in Git","description":"ArgoCD Application resource defines GitOps deployment with auto-sync and self-healing."},{"title":"CI/CD Deployment Pipeline","useCase":"Full deploy pipeline with rollback.","code":"name: Deploy to Production\non:\n  push:\n    branches: [main]\n\njobs:\n  deploy:\n    runs-on: ubuntu-latest\n    environment: production\n    steps:\n      - uses: actions/checkout@v4\n\n      - name: Build and push Docker image\n        run: |\n          docker build -t myapp:${{ github.sha }} .\n          docker push myapp:${{ github.sha }}\n\n      - name: Deploy to staging\n        run: ./deploy.sh staging ${{ github.sha }}\n\n      - name: Staging health check\n        run: |\n          for i in {1..12}; do\n            STATUS=$(curl -s -o /dev/null -w \"%{http_code}\" https://staging.myapp.com/health)\n            if [ \"$STATUS\" = \"200\" ]; then exit 0; fi\n            sleep 5\n          done\n          exit 1\n\n      - name: Promote to production\n        run: ./deploy.sh production ${{ github.sha }}\n\n      - name: Post-deploy health check\n        run: |\n          if ! curl -f https://myapp.com/health; then\n            ./rollback.sh production\n            exit 1\n          fi","description":"Full deployment pipeline with staging verification and production rollout with health check."}],"mcqQuestions":[{"question":"What is blue-green deployment?","options":["Gradual traffic shift","Two environments switch traffic","Replace instances one by one","Stop and start"],"answer":1,"explanation":"Blue-green uses two identical environments and switches traffic between them for zero-downtime."},{"question":"What is canary deployment?","options":["Deploy all at once","Gradual traffic shift to new version","Two environments","Manual deployment"],"answer":1,"explanation":"Canary gradually shifts traffic from old to new version monitoring each step."},{"question":"What is immutable infrastructure?","options":["Patch running servers","Replace servers never modify","Manual configuration","Shared hosting"],"answer":1,"explanation":"Immutable infrastructure builds new images and replaces servers instead of patching running ones."},{"question":"What is Infrastructure as Code?","options":["Manual server setup","Infrastructure defined in version-controlled files","Graphical UI tools","Shell scripts only"],"answer":1,"explanation":"IaC defines infrastructure in code enabling review repeatability and audit trails."},{"question":"What is GitOps?","options":["Git as deployment source of truth","Git as backup tool","Git for code only","Git for documentation"],"answer":0,"explanation":"GitOps uses Git as the single source of truth for deployment state with automatic cluster sync."},{"question":"What triggers automatic rollback?","options":["Deployment complete","Health check failure","New PR opened","Code review approved"],"answer":1,"explanation":"Automatic rollback triggers when health checks fail after deployment."},{"question":"Deployment Automation — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Deployment Automation — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Deployment Automation — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Deployment Automation — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["git"]["git-release-mgmt"] = {"id":"git-release-mgmt","title":"Release Management","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Release management is the process of planning scheduling and controlling software builds through different stages to production.","Key elements: semantic versioning (MAJOR.MINOR.PATCH) release branches release notes changelogs and version bumping in CI/CD.","Release lifecycle: feature development to release branch to QA/stabilization to production release to hotfix if needed. Each release is tagged and immutable.","Tools: GitHub Releases GitLab Releases semantic-release (automated) release-drafter (auto-changelog). Releases should be automated version-bump merge to main and tag."],"laymanDefinition":"Release management is like a train schedule. Features are passengers waiting at the station (develop branch). Every two weeks a train (release branch) departs. Tickets are checked (QA testing). Passengers who miss the train wait for the next one. Sometimes an emergency express train (hotfix) runs on a special schedule. Each train has a unique number (version tag).","deepDive":[{"heading":"Semantic Versioning (SemVer)","text":"MAJOR: breaking changes (v2.0.0). MINOR: new features backward compatible (v1.1.0). PATCH: bug fixes backward compatible (v1.0.1). Pre-release: v1.0.0-beta.1 v1.0.0-rc.1. Build metadata: v1.0.0+build.456. Version defined in package.json or equivalent."},{"heading":"Release Branch Strategy","text":"Git Flow: release/v1.2 branched from develop. Only bug fixes and release tasks (no new features). Merged to main (tagged) and develop. GitHub Flow: no release branches. Tag on main after merge. Trunk-Based: release branches from main for stabilization."},{"heading":"Changelog Generation","text":"Conventional commits enable automated changelog. feat: adds to Features section. fix: adds to Bug Fixes. breaking changes: highlighted. Tools: conventional-changelog release-drafter semantic-release. Format: Keep a Changelog. Each release links to diff and release notes."},{"heading":"Release Automation (semantic-release)","text":"Fully automated release process. Analyzes commits since last release. Determines next version (major/minor/patch). Generates changelog. Creates Git tag. Publishes to npm/registry. Creates GitHub Release. Requires conventional commit format."},{"heading":"Hotfix Management","text":"Hotfix branch from main (or production tag). Fix the critical bug. Merge back to main (tag new patch version). Merge back to develop (if using Git Flow). Hotfixes skip the normal release cycle. Version bump: patch version (v1.0.1). Hotfixes should be rare; they indicate release process improvement needed."}],"interviewAnswer":"Release management brings predictability to shipping software. Use semantic versioning. Automate version bumps and changelogs with conventional commits and semantic-release. Use release branches for stabilization. Hotfixes should be rare. A good release process reduces stress and increases confidence in deployments.","interviewQuestions":[{"question":"What is release management?","answer":"Planning scheduling and controlling software builds through stages to production."},{"question":"What is semantic versioning?","answer":"MAJOR.MINOR.PATCH: breaking changes new features backward compatible bug fixes backward compatible."},{"question":"What is a release branch?","answer":"A branch for stabilizing a release. Only bug fixes and release tasks. Merged to main and develop."},{"question":"What are release notes?","answer":"Documentation accompanying a release listing features fixes and breaking changes."},{"question":"What is semantic-release?","answer":"An automated release tool that determines version generates changelog creates tag and publishes."},{"question":"What is a changelog?","answer":"A curated list of notable changes for each version of a project."},{"question":"What is a hotfix?","answer":"An urgent fix for a production issue. Branched from main merged back and tagged as patch version."},{"question":"What triggers a MAJOR version bump?","answer":"Breaking changes that are not backward compatible."},{"question":"What triggers a MINOR version bump?","answer":"New features that are backward compatible."},{"question":"What triggers a PATCH version bump?","answer":"Bug fixes that are backward compatible."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Release Management</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Feature Dev</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Develop branch</text><line x1=\"110\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"140\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"190\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Release Branch</text><text x=\"190\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Stabilize QA</text><line x1=\"240\" y1=\"48\" x2=\"260\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Tag v1.0.0</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Immutable marker</text><rect x=\"140\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"190\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy Prod</text><text x=\"190\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Release to users</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Changelog</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Document changes</text><rect x=\"140\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"190\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Hotfix</text><text x=\"190\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Patch production</text><rect x=\"260\" y=\"35\" width=\"220\" height=\"150\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"370\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Release Management</text><text x=\"370\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Semantic versioning release branches changelogs hotfixes. Automated with semantic-release and conventional commits.</text><text x=\"100\" y=\"210\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Release Management: Plan schedule control releases. Semantic versioning release branches changelogs hotfix automation.</text></svg>","codeExamples":[{"title":"Semantic Release Configuration","useCase":"Automated release setup.","code":"// release.config.js\nmodule.exports = {\n  branches: ['main', { name: 'next', prerelease: true }],\n  plugins: [\n    '@semantic-release/commit-analyzer',\n    '@semantic-release/release-notes-generator',\n    '@semantic-release/changelog',\n    [\"@semantic-release/npm\", { npmPublish: true }],\n    \"@semantic-release/github\",\n    [\"@semantic-release/git\", {\n      assets: ['package.json', 'CHANGELOG.md'],\n      message: \"chore(release): ${nextRelease.version} [skip ci]\"\n    }]\n  ]\n};\n\n# CI step:\n# npx semantic-release","description":"semantic-release config: analyzes commits bumps version generates changelog creates tag and GitHub release."},{"title":"Changelog Generation (conventional-changelog)","useCase":"Auto-generate changelog.","code":"# Install conventional-changelog-cli\n# npm install -g conventional-changelog-cli\n\n# Generate changelog from conventional commits\nconventional-changelog -p angular -i CHANGELOG.md -s\n\n# Output format:\n# # Changelog\n# \n# ## [1.2.0] - 2024-03-15\n# \n# ### Features\n# * add payment gateway ([a1b2c3d])\n# * add search functionality ([b2c3d4e])\n# \n# ### Bug Fixes\n# * fix login timeout ([c3d4e5f])\n# * fix memory leak ([d4e5f6g])\n# \n# ### Breaking Changes\n# * upgrade to API v2 ([e5f6g7h])\n\n# Use release-drafter for GitHub:\n# .github/release-drafter.yml","description":"conventional-changelog generates release notes automatically from conventional commit messages."},{"title":"GitHub Release Workflow","useCase":"Automated release on tag push.","code":"name: Create Release\non:\n  push:\n    tags:\n      - \"v*\"\n\njobs:\n  release:\n    runs-on: ubuntu-latest\n    permissions:\n      contents: write\n    steps:\n      - uses: actions/checkout@v4\n\n      - name: Generate release notes\n        id: notes\n        run: |\n          PREV_TAG=$(git describe --tags --abbrev=0 HEAD^ 2>/dev/null || echo '')\n          NOTES=$(conventional-changelog -p angular)\n          echo \"notes<<EOF\" >> $GITHUB_OUTPUT\n          echo \"$NOTES\" >> $GITHUB_OUTPUT\n          echo \"EOF\" >> $GITHUB_OUTPUT\n\n      - name: Create GitHub Release\n        uses: softprops/action-gh-release@v1\n        with:\n          body: ${{ steps.notes.outputs.notes }}\n          draft: false\n          prerelease: ${{ contains(github.ref, '-') }}","description":"GitHub Actions workflow that creates a release with auto-generated notes when a version tag is pushed."},{"title":"Release Branch Workflow (Git Flow)","useCase":"Manage release branches.","code":"# Start a release\ngit checkout develop\ngit checkout -b release/v1.2.0\n\n# Stabilize (only bug fixes)\ngit commit -m \"fix: correct payment calculation\"\ngit commit -m \"fix: update API rate limit\"\n\n# Version bump in release branch\necho \"v1.2.0\" > VERSION\ngit add VERSION\ngit commit -m \"chore: bump version to 1.2.0\"\n\n# Merge to main and tag\ngit checkout main\ngit merge --no-ff release/v1.2.0\ngit tag -a v1.2.0 -m \"Release v1.2.0\"\ngit push origin main --tags\n\n# Merge back to develop\ngit checkout develop\ngit merge --no-ff release/v1.2.0\n\n# Delete release branch\ngit branch -d release/v1.2.0","description":"Git Flow release branch workflow: branch stabilize merge to main tag and merge back to develop."},{"title":"Hotfix Workflow","useCase":"Emergency production fix.","code":"# From main (or production tag)\ngit checkout main\ngit checkout -b hotfix/critical-security\n\n# Fix the critical bug\ngit commit -m \"fix: patch SQL injection vulnerability\"\n\n# Merge to main and tag patch\ngit checkout main\ngit merge --no-ff hotfix/critical-security\ngit tag -a v1.0.1 -m \"Hotfix v1.0.1\"\ngit push origin main --tags\n\n# If using Git Flow merge to develop too\ngit checkout develop\ngit merge --no-ff hotfix/critical-security\n\n# The hotfix version bump is a PATCH\n# v1.0.0 -> v1.0.1 (not v1.1.0)","description":"Hotfix workflow: branch from main fix merge to main tag patch version and merge back to develop."}],"mcqQuestions":[{"question":"What is semantic versioning?","options":["Random version numbers","MAJOR.MINOR.PATCH with meaning","Date-based versions","Build numbers only"],"answer":1,"explanation":"SemVer defines version meaning: MAJOR (breaking) MINOR (feature) PATCH (fix)."},{"question":"What is a release branch?","options":["Branch for daily work","Stabilization branch before release","Branch for experiments","Branch for documentation"],"answer":1,"explanation":"Release branch stabilizes a release with only bug fixes before merging to main."},{"question":"What does semantic-release do?","options":["Manual release process","Automated version bump changelog tag release","Code formatting","Test runner"],"answer":1,"explanation":"semantic-release fully automates the release process from commit analysis to publishing."},{"question":"What triggers a MAJOR version?","options":["Bug fixes","Breaking changes","New features","Documentation updates"],"answer":1,"explanation":"MAJOR version increments when backward-incompatible changes are introduced."},{"question":"What is a hotfix?","options":["A new feature","An urgent production bug fix","A code refactor","A version upgrade"],"answer":1,"explanation":"Hotfix is an urgent fix for a production issue branched from main and tagged as patch."},{"question":"What should release notes include?","options":["Only version number","Features fixes and breaking changes","Full commit log","Random updates"],"answer":1,"explanation":"Release notes should summarize features bug fixes and breaking changes for the release."},{"question":"Release Management — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Release Management — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Release Management — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Release Management — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};